/**
 * Kortix Continuation — Configuration
 *
 * Always-on passive auto-continuation. When a session goes idle with unfinished
 * tracked work (native opencode todos), the runtime re-prompts the agent to keep
 * going instead of letting it self-stop mid-task.
 *
 * This module ships ONLY the passive todo enforcer: no /autowork loop, no keyword
 * activation, no algorithm variants. Keep it small.
 */

// ─── Constants ────────────────────────────────────────────────────────────────

/** Marker appended to every system-injected continuation prompt so the enforcer
 *  never mistakes its own injection for a real user message. */
export const INTERNAL_MARKER = "<!-- KORTIX_INTERNAL -->"

// ─── Feature Toggles ─────────────────────────────────────────────────────────

export interface ContinuationFeatures {
	/** Master switch — session.idle → auto-continue */
	continuation: boolean
	/** Check native todos for unfinished tracked work */
	todoEnforcer: boolean
	/** Classify the last assistant turn before continuing (stop on Q&A / blocked / done) */
	intentGate: boolean
}

// ─── Thresholds & Limits ─────────────────────────────────────────────────────

export interface ContinuationThresholds {
	/** Grace period (ms) after an abort/error event — skip continuation during this window */
	abortGracePeriodMs: number
	/** Min time (ms) the agent must have been working before continuation kicks in */
	minWorkDurationMs: number
	/** Max continuations per user request (absolute safety cap, reset on each new user message) */
	maxSessionContinuations: number
	/** Max consecutive aborts/empty responses before continuation gives up for this request */
	maxConsecutiveAborts: number
	/** Cooldown (ms) between continuation attempts — prevents spam */
	passiveCooldownMs: number
}

// ─── Full Config ──────────────────────────────────────────────────────────────

export interface ContinuationConfig {
	features: ContinuationFeatures
	thresholds: ContinuationThresholds
}

// ─── Defaults ─────────────────────────────────────────────────────────────────

export const DEFAULT_FEATURES: ContinuationFeatures = {
	continuation: true,
	todoEnforcer: true,
	intentGate: true,
}

export const DEFAULT_THRESHOLDS: ContinuationThresholds = {
	abortGracePeriodMs: 3_000, // 3s grace after abort/error events
	minWorkDurationMs: 8_000, // agent must have worked at least 8s before continuation kicks in
	maxSessionContinuations: 50, // per user request — high; this is a safety net, not the expected path
	maxConsecutiveAborts: 3, // 3 consecutive aborts/empty responses → stop continuation for this request
	passiveCooldownMs: 5_000, // 5s minimum between continuation attempts
}

export const DEFAULT_CONFIG: ContinuationConfig = {
	features: { ...DEFAULT_FEATURES },
	thresholds: { ...DEFAULT_THRESHOLDS },
}

// ─── Runtime State ────────────────────────────────────────────────────────────

/** Mutable per-session runtime state for the continuation engine. */
export interface ContinuationState {
	/** Session ID being tracked */
	sessionId: string | null
	/** Continuations injected for the current user request */
	totalSessionContinuations: number
	/** Timestamp when the current work cycle started (the last real user message) */
	workCycleStartedAt: number
	/** Consecutive aborted/empty responses — circuit breaker */
	consecutiveAborts: number
	/** Timestamp of the last abort/error — for the grace period */
	lastAbortAt: number
	/** Timestamp of the last continuation attempt — for the cooldown */
	lastContinuationAt: number
	/** Whether a continuation prompt is currently in-flight (prevents double-fire) */
	inflight: boolean
	/** ID of the last real (non-internal) user message seen — drives per-request budget reset */
	lastUserMessageId: string | null
}

export function createInitialState(): ContinuationState {
	return {
		sessionId: null,
		totalSessionContinuations: 0,
		workCycleStartedAt: 0,
		consecutiveAborts: 0,
		lastAbortAt: 0,
		lastContinuationAt: 0,
		inflight: false,
		lastUserMessageId: null,
	}
}

// ─── Config Helpers ───────────────────────────────────────────────────────────

/** Merge partial config into defaults. */
export function mergeConfig(partial: Partial<ContinuationConfig>): ContinuationConfig {
	return {
		features: { ...DEFAULT_FEATURES, ...partial.features },
		thresholds: { ...DEFAULT_THRESHOLDS, ...partial.thresholds },
	}
}

/**
 * Continuation Engine — session.idle evaluator
 *
 * Combines signals from IntentGate and TodoEnforcer to decide whether to inject
 * a continuation prompt when the session goes idle. Pure function — no I/O, no
 * LLM calls — so it is fully unit-testable.
 *
 * Decision flow:
 *   1. Feature check — continuation must be enabled
 *   2. Empty/aborted response → stop (don't loop on a crash)
 *   3. Safety limits — per-request cap, min work duration, abort circuit breaker, cooldown
 *   4. IntentGate — classify last assistant message (stop on completed/blocked/answer)
 *   5. TodoEnforcer — continue while native todos remain unfinished
 *   6. Default → stop (conservative)
 */

import type { Todo } from "@opencode-ai/sdk"
import { type ContinuationConfig, type ContinuationState, INTERNAL_MARKER } from "./config"
import { classifyIntent, type IntentResult } from "./intent-gate"
import { evaluateTodos, formatRemainingWork, type TodoEnforcerResult } from "./todo-enforcer"

// ─── Decision Types ───────────────────────────────────────────────────────────

export type ContinuationAction = "continue" | "stop"

export interface ContinuationDecision {
	action: ContinuationAction
	/** The prompt to inject if action === "continue" */
	prompt: string | null
	/** Human-readable reason for the decision (logged, not sent to model) */
	reason: string
	/** Signal sources that informed the decision */
	signals: {
		intent?: IntentResult
		todo?: TodoEnforcerResult
		safetyCheck?: string
	}
}

// ─── Safety Checks ────────────────────────────────────────────────────────────

function checkSafetyLimits(config: ContinuationConfig, state: ContinuationState): string | null {
	const now = Date.now()

	// Per-request limit
	if (state.totalSessionContinuations >= config.thresholds.maxSessionContinuations) {
		return `max continuations reached (${config.thresholds.maxSessionContinuations})`
	}

	// Min work duration (don't continue if the agent barely started)
	if (state.workCycleStartedAt > 0 && now - state.workCycleStartedAt < config.thresholds.minWorkDurationMs) {
		return `min work duration not met (${config.thresholds.minWorkDurationMs}ms)`
	}

	// Circuit breaker: too many consecutive aborts/empty responses
	if (state.consecutiveAborts >= config.thresholds.maxConsecutiveAborts) {
		return `circuit breaker: ${state.consecutiveAborts} consecutive aborts/empty responses`
	}

	// Cooldown: minimum time between continuation attempts
	if (state.lastContinuationAt > 0) {
		const elapsed = now - state.lastContinuationAt
		if (elapsed < config.thresholds.passiveCooldownMs) {
			return `cooldown: ${Math.round((config.thresholds.passiveCooldownMs - elapsed) / 1000)}s remaining`
		}
	}

	// Abort grace period: skip continuation shortly after an abort/error
	if (state.lastAbortAt > 0) {
		const timeSinceAbort = now - state.lastAbortAt
		if (timeSinceAbort < config.thresholds.abortGracePeriodMs) {
			return `abort grace period: ${Math.round((config.thresholds.abortGracePeriodMs - timeSinceAbort) / 1000)}s remaining`
		}
	}

	// In-flight guard: prevent double-fire race condition
	if (state.inflight) {
		return "continuation already in-flight — skipping to prevent double-fire"
	}

	return null
}

// ─── Continuation Prompt Builder ─────────────────────────────────────────────

function buildContinuationPrompt(todoResult: TodoEnforcerResult | null, state: ContinuationState): string {
	const parts: string[] = []

	parts.push("[SYSTEM REMINDER - TODO CONTINUATION]")
	parts.push("You have unfinished work. Continue from where you left off — do not stop.")
	parts.push(`Continuations so far this request: ${state.totalSessionContinuations}.`)

	if (todoResult && todoResult.remainingItems.length > 0) {
		parts.push("")
		parts.push(formatRemainingWork(todoResult))
	}

	parts.push("")
	parts.push(
		"Pick up the next pending/in-progress item and keep working until every todo is completed or genuinely blocked. Do not re-explain what was already done. If you are truly blocked on the user or an external dependency, state the blocker explicitly and ask.",
	)
	parts.push(INTERNAL_MARKER)

	return parts.join("\n")
}

// ─── Main Evaluator ───────────────────────────────────────────────────────────

/**
 * Evaluate whether a session should continue after going idle.
 *
 * Open todos are AUTHORITATIVE: if tracked work remains, we continue — even if
 * the agent's final message was empty, a short note, or a premature "all done"
 * claim. This is the whole point of the enforcer: never self-stop mid-task.
 *
 * The only things that override open todos are (in order): the safety breakers,
 * a real pending-question tool (handled by the plugin before this runs), and a
 * hard external blocker (missing credentials / unreachable dependency) where the
 * agent genuinely cannot proceed. Rhetorical "should I...?" text does NOT stop a
 * session with open work — the agent must escalate via the question tool, which
 * the plugin detects reliably.
 */
export function evaluate(
	config: ContinuationConfig,
	state: ContinuationState,
	lastAssistantText: string,
	hadToolCalls: boolean,
	todos: Todo[],
): ContinuationDecision {
	if (!config.features.continuation) {
		return { action: "stop", prompt: null, reason: "continuation disabled", signals: {} }
	}

	// Safety breakers first: per-request cap, min work duration, abort circuit
	// breaker (bounds looping on repeated empty/crashed turns), cooldown, in-flight.
	const safetyViolation = checkSafetyLimits(config, state)
	if (safetyViolation) {
		return { action: "stop", prompt: null, reason: `safety: ${safetyViolation}`, signals: { safetyCheck: safetyViolation } }
	}

	// A genuine external blocker (missing API key/credentials, unreachable service)
	// means the agent cannot proceed regardless of open todos — stop and report.
	let intentResult: IntentResult | undefined
	if (config.features.intentGate) {
		intentResult = classifyIntent(lastAssistantText, hadToolCalls, todos)
		if (intentResult.intent === "blocked-external") {
			return { action: "stop", prompt: null, reason: "intent: blocked on external dependency", signals: { intent: intentResult } }
		}
	}

	// Todos are authoritative.
	if (config.features.todoEnforcer) {
		const todoResult = evaluateTodos(todos)
		if (todoResult.verdict === "unfinished") {
			return {
				action: "continue",
				prompt: buildContinuationPrompt(todoResult, state),
				reason: `todos: ${todoResult.reason}`,
				signals: { intent: intentResult, todo: todoResult },
			}
		}
		// "done" (incl. no tracked work) or "blocked" (all remaining items await
		// an external condition) → stop. Nothing for the enforcer to drive.
		return { action: "stop", prompt: null, reason: `todos: ${todoResult.reason}`, signals: { intent: intentResult, todo: todoResult } }
	}

	return { action: "stop", prompt: null, reason: "todo enforcer disabled", signals: { intent: intentResult } }
}

import { INTERNAL_MARKER } from "./config"

const CONTINUATION_MESSAGE_PREFIX = "msg_kxcont_"

/** Concatenate all text-part content of a message. */
export function messageFullText(msg: any): string {
	let text = ""
	for (const part of msg?.parts ?? []) {
		if (part?.type === "text" && typeof part.text === "string") text += `${part.text}\n`
	}
	return text
}

/** True if a message was injected by the system and must never count as real user input. */
export function isInternalMessage(text: string): boolean {
	if (text.includes(INTERNAL_MARKER)) return true
	if (text.includes("[SYSTEM REMINDER")) return true
	if (text.includes("<kortix_system")) return true
	return false
}

export function isPassiveContinuationMessage(text: string): boolean {
	if (!isInternalMessage(text)) return false
	if (!text.includes('source="kortix-continuation"')) return false
	if (!text.includes('type="passive-continuation"')) return false
	return true
}

export function countPassiveContinuationsAfter(messages: any[], lastUserId: string | null): number {
	if (!lastUserId) return 0
	let seenLastUser = false
	let count = 0
	for (const msg of messages) {
		if (msg?.info?.role === "user" && String(msg?.info?.id ?? "") === lastUserId) {
			seenLastUser = true
			continue
		}
		if (!seenLastUser) continue
		if (msg?.info?.role !== "user") continue
		if (isPassiveContinuationMessage(messageFullText(msg))) count++
	}
	return count
}

function stableHash(input: string): string {
	let hash = 0x811c9dc5
	for (let i = 0; i < input.length; i++) {
		hash ^= input.charCodeAt(i)
		hash = Math.imul(hash, 0x01000193)
	}
	return (hash >>> 0).toString(36)
}

export function continuationMessageId(sessionId: string, lastUserId: string | null, continuationIndex: number): string {
	return `${CONTINUATION_MESSAGE_PREFIX}${stableHash(`${sessionId}:${lastUserId ?? "none"}:${continuationIndex}`)}`
}

export function hasContinuationMessageId(messages: any[], messageId: string): boolean {
	return messages.some((msg) => String(msg?.info?.id ?? "") === messageId)
}

/**
 * Intent Gate — Lightweight turn classifier
 *
 * Classifies the last assistant message to determine whether continuation is
 * appropriate. Keeps the engine from looping on conversational turns,
 * user-blocked states, or answer-only responses.
 *
 * Classification is heuristic-based (no LLM call). The goal is to catch obvious
 * stop-cases cheaply before the engine consults todo state.
 */

import type { Todo } from "@opencode-ai/sdk"

// ─── Intent Types ────────────────────────────────────────────────────────────

export type Intent =
	| "answer" // Simple Q&A — no continuation needed
	| "executing" // Actively working on a task (tool calls present)
	| "planning" // Laid out a plan, may need to execute
	| "blocked-human" // Waiting on the user for input/decision/credentials
	| "blocked-external" // Waiting on external dependency (OAuth, API key, etc.)
	| "blocked-question" // Waiting for user to answer a question tool call
	| "completed" // Explicitly signaled completion
	| "unknown" // Can't classify — fall through to other signals

export interface IntentResult {
	intent: Intent
	reason: string
	shouldContinue: boolean
}

// ─── Classification ──────────────────────────────────────────────────────────

// Patterns that indicate the assistant is waiting on the user
const BLOCKED_HUMAN_PATTERNS = [
	/(?:should i|shall i|would you like|do you want|let me know|please confirm|waiting for your)/i,
	/(?:which (?:option|approach|one)|what do you (?:think|prefer))/i,
	/(?:before i proceed|proceed with|go ahead with)/i,
	/(?:could you (?:provide|share|clarify|specify))/i,
	/(?:i need you to|please (?:provide|share|specify|tell me))/i,
	/(?:can you (?:provide|share|clarify|confirm|let me know))/i,
	/(?:your (?:input|feedback|approval|confirmation|decision) (?:is needed|needed|required))/i,
	/(?:once you(?:'ve)? (?:decided|confirmed|reviewed|provided))/i,
	/(?:how would you like|what would you like me to)/i,
]

// Patterns that indicate external blockers
const BLOCKED_EXTERNAL_PATTERNS = [
	/(?:api key|api_key|token|credential|secret|password).*(?:not set|missing|required|needed|unavailable)/i,
	/(?:oauth|authorization|authenticate).*(?:required|needed|first)/i,
	/(?:connect|configure|set up).*(?:first|before)/i,
	/(?:environment variable|env var).*(?:not set|missing|required)/i,
	/(?:cannot|can't|unable to) (?:access|connect|reach|authenticate)/i,
]

// Patterns that indicate explicit completion — require strong, specific signal words.
// Deliberately conservative: prefer false negatives over false positives.
// (We do NOT match bare "done" — too many false positives in work-in-progress messages.)
const COMPLETION_PATTERNS = [
	// "all tasks/items/todos are completed/done/finished"
	/(?:all (?:tasks?|items?|todos?|steps?) (?:are )?(?:now )?(?:completed?|done|finished))/i,
	// "everything is done/complete/finished"
	/(?:everything (?:is (?:now )?)?(?:done|complete|finished))/i,
	// "the task/work/implementation is complete"
	/(?:the (?:task|work|implementation|feature|refactor) (?:is (?:now )?)?(?:complete|done|finished))/i,
	// "successfully completed/implemented/deployed/shipped [something]"
	/(?:successfully (?:completed?|implemented|deployed|shipped|finished)) (?:all|the|this)/i,
	// "implementation/refactoring/migration is complete"
	/(?:implementation|refactoring|migration|integration) (?:is (?:now )?)?(?:complete|done|finished)/i,
]

// Patterns that indicate answer-only (no action taken)
const ANSWER_ONLY_PATTERNS = [
	/(?:^here'?s? (?:the|an|a) (?:explanation|answer|summary))/i,
	/(?:^in (?:short|summary|brief)[,:])/i,
	/(?:^to answer your question)/i,
	/(?:^the (?:answer|reason|explanation) is)/i,
	/(?:^(?:yes|no)[,.]?\s+(?:the|this|that|you|it))/i,
]

// Patterns indicating the agent is reporting completed work (stop passive continuation)
const REPORTING_PATTERNS = [
	/(?:^|\n)(?:here(?:'s| is) what i (?:did|changed|implemented|added|fixed))/i,
	/(?:^|\n)(?:i(?:'ve| have) (?:completed?|finished|implemented|added|fixed|updated|refactored))/i,
	/(?:^|\n)(?:the (?:following|above) (?:changes|modifications|updates) (?:have been|were) made)/i,
]

// Patterns that indicate the agent used the question tool (awaiting user answer)
const PENDING_QUESTION_PATTERNS = [
	/\[question tool\]/i,
	/awaiting your (response|answer|input)/i,
	/please (answer|respond to) (the|this) question/i,
]

// Patterns indicating a plan was laid out
const PLANNING_PATTERNS = [
	/(?:here'?s? (?:the|my|a) plan)/i,
	/(?:i'?ll|i will|let me) (?:start|begin) (?:by|with)/i,
	/(?:step \d|phase \d|first,? i'?ll)/i,
	/(?:the approach|my approach|implementation plan)/i,
	/(?:plan of action|here'?s? (?:how|what) i'?ll)/i,
]

/**
 * Classify the last assistant message to determine if continuation is appropriate.
 *
 * @param lastAssistantText - The text content of the last assistant message
 * @param hadToolCalls - Whether the assistant's last turn included tool calls
 * @param todos - Current todo state (if available)
 */
export function classifyIntent(lastAssistantText: string, hadToolCalls: boolean, todos?: Todo[]): IntentResult {
	const text = lastAssistantText.trim()

	// Empty response — likely still processing or error
	if (!text && !hadToolCalls) {
		return { intent: "unknown", reason: "empty response", shouldContinue: false }
	}

	// 0. Check for pending question (agent waiting for user answer)
	for (const pattern of PENDING_QUESTION_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "blocked-question", reason: "pending question awaiting user", shouldContinue: false }
		}
	}

	// 1. Check for explicit completion signals (strong signals only)
	for (const pattern of COMPLETION_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "completed", reason: "explicit completion signal", shouldContinue: false }
		}
	}

	// 2. Check for external blockers (higher priority than human-blocked)
	for (const pattern of BLOCKED_EXTERNAL_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "blocked-external", reason: "waiting on external dependency", shouldContinue: false }
		}
	}

	// 3. Check for human-blocked state
	for (const pattern of BLOCKED_HUMAN_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "blocked-human", reason: "waiting on user input", shouldContinue: false }
		}
	}

	// 4. If the turn had tool calls, the agent was actively working
	if (hadToolCalls) {
		return { intent: "executing", reason: "tool calls present", shouldContinue: true }
	}

	// 5. Check if this looks like a plan (planning → might need to continue to execute)
	for (const pattern of PLANNING_PATTERNS) {
		if (pattern.test(text)) {
			// Only continue if there are pending todos
			const hasPendingWork = todos?.some((t) => t.status === "pending" || t.status === "in_progress")
			return {
				intent: "planning",
				reason: hasPendingWork ? "plan with pending work" : "plan laid out",
				shouldContinue: hasPendingWork ?? false,
			}
		}
	}

	// 6. Check for reporting patterns (agent just summarized what it did)
	for (const pattern of REPORTING_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "completed", reason: "agent reporting completed work", shouldContinue: false }
		}
	}

	// 7. Check for answer-only patterns
	for (const pattern of ANSWER_ONLY_PATTERNS) {
		if (pattern.test(text)) {
			return { intent: "answer", reason: "answer-only response", shouldContinue: false }
		}
	}

	// 8. Short text without tool calls — likely conversational
	// 300 chars: enough room for brief work summaries but catches most pure Q&A
	if (text.length < 300 && !hadToolCalls) {
		return { intent: "answer", reason: "short response without tools", shouldContinue: false }
	}

	// 9. Fall through — can't classify, let other signals decide
	return { intent: "unknown", reason: "unclassified", shouldContinue: false }
}

/**
 * Kortix Continuation — Todo Continuation Enforcer
 *
 * Always-on auto-continuation. When a root session goes idle with unfinished
 * tracked work (native opencode todos), the runtime re-prompts the agent to keep
 * going instead of letting it self-stop mid-task.
 *
 * Pipeline (no LLM calls), on `session.idle`:
 *   - skip subagents, pending questions, and empty/aborted turns
 *   - IntentGate   → stop on completion / blocked-on-user / answer-only
 *   - TodoEnforcer → continue while native todos remain unfinished
 *   - safety gates → per-request cap, cooldown, circuit breaker, in-flight guard
 *   - client.session.promptAsync(<continuation reminder>)
 *
 * This intentionally ships ONLY the passive enforcer — no /autowork loop, no
 * keyword activation, no algorithm variants. Set KORTIX_CONTINUATION_DISABLED=1
 * to turn it off.
 *
 * Hooks:
 *   event → session.idle (evaluate + inject), session.error/aborted (grace),
 *           session.deleted (cleanup)
 */

import { type Plugin } from "@opencode-ai/plugin"
import type { Todo } from "@opencode-ai/sdk"
import { type ContinuationState, createInitialState, DEFAULT_CONFIG } from "./config"
import {
	continuationMessageId,
	countPassiveContinuationsAfter,
	hasContinuationMessageId,
	isInternalMessage,
	messageFullText,
} from "./dedupe"
import { evaluate } from "./continuation-engine"

const DISABLED = process.env.KORTIX_CONTINUATION_DISABLED === "1" || process.env.KORTIX_CONTINUATION_DISABLED === "true"

// ─── Message helpers ───────────────────────────────────────────────────────────

/** Last assistant message text + whether that turn made tool calls. */
function extractLastAssistantMessage(messages: any[]): { text: string; hadToolCalls: boolean } {
	let text = ""
	let hadToolCalls = false
	for (let i = messages.length - 1; i >= 0; i--) {
		const msg = messages[i]
		if (msg?.info?.role === "assistant") {
			for (const part of msg.parts ?? []) {
				if (part?.type === "text" && !part.synthetic && !part.ignored) text += `${part.text}\n`
				if (part?.type === "tool") hadToolCalls = true
			}
			break
		}
	}
	return { text: text.trim(), hadToolCalls }
}

/** Most recent real (non-internal) user message — drives the per-request budget reset. */
function findLastRealUserMessage(messages: any[]): { id: string; createdAt: number } | null {
	for (let i = messages.length - 1; i >= 0; i--) {
		const msg = messages[i]
		if (msg?.info?.role !== "user") continue
		if (isInternalMessage(messageFullText(msg))) continue
		return { id: String(msg?.info?.id ?? i), createdAt: Number(msg?.info?.time?.created ?? 0) || 0 }
	}
	return null
}

/**
 * Detect if the agent is waiting for a user answer to a `question` tool call.
 * Walks backwards — true if an assistant `question` tool call (running/pending)
 * is found before any subsequent user message.
 */
function hasPendingQuestion(messages: any[]): boolean {
	for (let i = messages.length - 1; i >= 0; i--) {
		const msg = messages[i]
		const role = msg?.info?.role
		if (role === "user") return false
		if (role !== "assistant") continue
		for (const part of msg.parts ?? []) {
			if (part?.type !== "tool") continue
			const toolName = (part.tool ?? part.toolName ?? part.tool_name ?? part.name ?? "") as string
			if (toolName === "question" || toolName === "mcp_question") {
				const status = part.state?.status ?? ""
				if (status === "running" || status === "pending") return true
			}
		}
	}
	return false
}

/** Wrap an injected prompt so the frontend renders it as a system block (not a user bubble). */
function wrapSystemPrompt(text: string, type: string): string {
	return `<kortix_system type="${type}" source="kortix-continuation">\n${text}\n</kortix_system>`
}

// ─── Plugin ────────────────────────────────────────────────────────────────────

const KortixContinuationPlugin: Plugin = async ({ client }) => {
	const config = DEFAULT_CONFIG
	const states = new Map<string, { state: ContinuationState; touched: number }>()
	const rootCache = new Map<string, boolean>()
	let lastGcAt = Date.now()
	const GC_INTERVAL_MS = 10 * 60_000
	const TTL_MS = 2 * 60 * 60_000

	const log = (level: "info" | "warn" | "error", message: string) => {
		try {
			client.app.log({ body: { service: "kortix-continuation", level, message } }).catch(() => {})
		} catch {
			// ignore logging failures
		}
	}

	const sid = (sessionId: string) => (sessionId.length > 16 ? sessionId.slice(-12) : sessionId)

	function getState(sessionId: string): ContinuationState {
		const now = Date.now()
		if (now - lastGcAt > GC_INTERVAL_MS) {
			lastGcAt = now
			for (const [key, entry] of states) {
				if (now - entry.touched > TTL_MS) {
					states.delete(key)
					rootCache.delete(key)
				}
			}
		}
		let entry = states.get(sessionId)
		if (!entry) {
			entry = { state: { ...createInitialState(), sessionId }, touched: now }
			states.set(sessionId, entry)
		}
		entry.touched = now
		return entry.state
	}

	/** Continuation applies to user-facing root sessions only — never subagents. */
	async function isRootSession(sessionId: string): Promise<boolean> {
		const cached = rootCache.get(sessionId)
		if (cached !== undefined) return cached
		try {
			const res = await client.session.get({ path: { id: sessionId } })
			const parentID = (res?.data as any)?.parentID
			const root = !parentID
			rootCache.set(sessionId, root)
			return root
		} catch {
			return true // fail open — treat unknown sessions as root
		}
	}

	return {
		event: async ({ event }: { event: any }) => {
			try {
				if (event.type === "session.deleted") {
					const id = event.properties?.info?.id ?? event.properties?.sessionID
					if (id) {
						states.delete(id)
						rootCache.delete(id)
					}
					return
				}

				if (event.type === "session.error" || event.type === "session.aborted") {
					const id = event.properties?.sessionID
					if (!id || !states.has(id)) return
					const state = getState(id)
					state.lastAbortAt = Date.now()
					state.consecutiveAborts++
					state.inflight = false
					return
				}

				if (event.type !== "session.idle") return
				if (DISABLED) return

				const sessionId = event.properties?.sessionID as string | undefined
				if (!sessionId) return
				if (!(await isRootSession(sessionId))) return

				const state = getState(sessionId)

				const [todoRes, messagesRes] = await Promise.all([
					client.session.todo({ path: { id: sessionId } }).catch(() => ({ data: [] as Todo[] })),
					client.session.messages({ path: { id: sessionId } }).catch(() => ({ data: [] as any[] })),
				])
				const todos = (todoRes.data ?? []) as Todo[]
				const messages = (messagesRes.data ?? []) as any[]

				// New real user message → fresh per-request budget.
				const lastUser = findLastRealUserMessage(messages)
				if (lastUser && lastUser.id !== state.lastUserMessageId) {
					state.lastUserMessageId = lastUser.id
					state.totalSessionContinuations = 0
					state.consecutiveAborts = 0
					state.lastContinuationAt = 0
					state.lastAbortAt = 0
					state.inflight = false
					state.workCycleStartedAt = lastUser.createdAt || Date.now()
				}
				const persistedContinuations = countPassiveContinuationsAfter(messages, state.lastUserMessageId)
				if (persistedContinuations > state.totalSessionContinuations) {
					state.totalSessionContinuations = persistedContinuations
				}

				if (hasPendingQuestion(messages)) {
					log("info", `[${sid(sessionId)}] skip: pending question`)
					return
				}

				const { text, hadToolCalls } = extractLastAssistantMessage(messages)
				if (!text.trim() && !hadToolCalls) state.consecutiveAborts++
				else state.consecutiveAborts = 0

				const decision = evaluate(config, state, text, hadToolCalls, todos)
				log("info", `[${sid(sessionId)}] ${decision.action} — ${decision.reason}`)

				if (decision.action === "continue" && decision.prompt) {
					const messageID = continuationMessageId(sessionId, state.lastUserMessageId, state.totalSessionContinuations)
					if (hasContinuationMessageId(messages, messageID)) {
						log("info", `[${sid(sessionId)}] skip: continuation ${messageID} already exists`)
						return
					}
					state.inflight = true
					state.totalSessionContinuations++
					state.lastContinuationAt = Date.now()
					await client.session
						.promptAsync({
							path: { id: sessionId },
							body: {
								messageID,
								parts: [{ type: "text" as const, text: wrapSystemPrompt(decision.prompt, "passive-continuation") }],
							},
						})
						.catch((err: unknown) => {
							log("warn", `[${sid(sessionId)}] promptAsync failed: ${err}`)
						})
						.finally(() => {
							state.inflight = false
						})
				}
			} catch (err) {
				log("warn", `event hook error: ${err}`)
			}
		},
	}
}

export default KortixContinuationPlugin

/**
 * Todo Enforcer — Detect unfinished tracked work
 *
 * Inspects the session's todo list (via client.session.todo()) and determines
 * whether there's unfinished work that should prevent the session from stopping.
 *
 * Three outcomes:
 *   - "done"       → All tracked work is complete or cancelled
 *   - "unfinished" → There are pending/in-progress items → should continue
 *   - "blocked"    → Work exists but appears blocked → should stop and report
 */

import type { Todo } from "@opencode-ai/sdk"

// ─── Types ───────────────────────────────────────────────────────────────────

export type TodoVerdict = "done" | "unfinished" | "blocked"

export interface TodoEnforcerResult {
	verdict: TodoVerdict
	reason: string
	/** Pending/in-progress items (for the continuation prompt) */
	remainingItems: Todo[]
	/** Total items in the todo list */
	totalItems: number
	/** Completed items */
	completedItems: number
}

// ─── Blocked detection ───────────────────────────────────────────────────────

// Heuristic: if a todo item's content mentions these, it's likely blocked
const BLOCKED_KEYWORDS = [
	"waiting",
	"blocked",
	"need.*from",
	"depends on",
	"after.*approval",
	"pending.*review",
	"requires.*access",
	"missing.*credentials",
]

function looksBlocked(todo: Todo): boolean {
	const text = todo.content.toLowerCase()
	return BLOCKED_KEYWORDS.some((kw) => new RegExp(kw, "i").test(text))
}

// ─── Enforcer ────────────────────────────────────────────────────────────────

/**
 * Evaluate a session's todo list to determine if work is complete.
 *
 * @param todos - The session's current todo list
 * @returns Verdict with remaining items and counts
 */
export function evaluateTodos(todos: Todo[]): TodoEnforcerResult {
	// No todos at all — can't enforce, treat as done
	if (!todos || todos.length === 0) {
		return {
			verdict: "done",
			reason: "no tracked work",
			remainingItems: [],
			totalItems: 0,
			completedItems: 0,
		}
	}

	const completed = todos.filter((t) => t.status === "completed" || t.status === "cancelled")
	const remaining = todos.filter((t) => t.status === "pending" || t.status === "in_progress")

	// All done
	if (remaining.length === 0) {
		return {
			verdict: "done",
			reason: `all ${todos.length} items completed`,
			remainingItems: [],
			totalItems: todos.length,
			completedItems: completed.length,
		}
	}

	// Check if remaining items look blocked
	const blockedItems = remaining.filter(looksBlocked)
	if (blockedItems.length > 0 && blockedItems.length === remaining.length) {
		// ALL remaining items look blocked — don't continue
		return {
			verdict: "blocked",
			reason: `${remaining.length} item(s) appear blocked`,
			remainingItems: remaining,
			totalItems: todos.length,
			completedItems: completed.length,
		}
	}

	// Unfinished work — should continue
	const inProgress = remaining.filter((t) => t.status === "in_progress")
	const pending = remaining.filter((t) => t.status === "pending")

	const parts: string[] = []
	if (inProgress.length > 0) parts.push(`${inProgress.length} in progress`)
	if (pending.length > 0) parts.push(`${pending.length} pending`)

	return {
		verdict: "unfinished",
		reason: `${remaining.length} remaining (${parts.join(", ")}) of ${todos.length} total`,
		remainingItems: remaining,
		totalItems: todos.length,
		completedItems: completed.length,
	}
}

/**
 * Build a concise reminder of remaining work for the continuation prompt.
 */
export function formatRemainingWork(result: TodoEnforcerResult): string {
	if (result.remainingItems.length === 0) return ""

	const lines = [`[TODO ENFORCER] ${result.completedItems}/${result.totalItems} complete. Remaining:`]
	for (const item of result.remainingItems) {
		const status = item.status === "in_progress" ? "🔄" : "⬜"
		const priority = item.priority === "high" ? " ❗" : ""
		lines.push(`  ${status} ${item.content}${priority}`)
	}
	return lines.join("\n")
}

