import type { PluginClient } from '../types.ts'
import { allStructured } from './wildcard.ts'

type PermissionAction = 'allow' | 'ask' | 'deny'
type BashPermissions = PermissionAction | Record<string, PermissionAction>

interface PermissionConfig {
  bash?: BashPermissions
  external_directory?: PermissionAction
}

let _client: PluginClient | null = null
let _directory: string | null = null

export function initPermissions(client: PluginClient, directory: string): void {
  _client = client
  _directory = directory
}

async function getPermissionConfig(): Promise<PermissionConfig> {
  if (!_client) {
    return {}
  }
  try {
    const response = await _client.config.get()
    if (response.error || !response.data) {
      return {}
    }
    return (response.data as { permission?: PermissionConfig }).permission ?? {}
  } catch {
    return {}
  }
}

async function showToast(
  message: string,
  variant: 'info' | 'success' | 'error' = 'info'
): Promise<void> {
  if (!_client) return
  try {
    await _client.tui.showToast({ body: { message, variant } })
  } catch {
    // Ignore toast errors
  }
}

async function denyWithToast(msg: string, details?: string): Promise<never> {
  await showToast(msg, 'error')
  throw new Error(details ? `${msg} ${details}` : msg)
}

async function handleAskPermission(commandLine: string): Promise<never> {
  await denyWithToast(
    `PTY: Command "${commandLine}" requires permission (treated as denied)`,
    `PTY spawn denied: Command "${commandLine}" requires user permission which is not supported by this plugin. Configure explicit "allow" or "deny" in your opencode.json permission.bash settings.`
  )
  throw new Error('Unreachable') // For TS, should never hit.
}

export async function checkCommandPermission(command: string, args: string[]): Promise<void> {
  const config = await getPermissionConfig()
  const bashPerms = config.bash

  if (!bashPerms) {
    return
  }

  if (typeof bashPerms === 'string') {
    if (bashPerms === 'deny') {
      await denyWithToast('PTY spawn denied: All bash commands are disabled by user configuration.')
    }
    if (bashPerms === 'ask') {
      await handleAskPermission(command)
    }
    return
  }

  const action = allStructured({ head: command, tail: args }, bashPerms)

  if (action === 'deny') {
    await denyWithToast(
      `PTY spawn denied: Command "${command} ${args.join(' ')}" is explicitly denied by user configuration.`
    )
  }

  if (action === 'ask') {
    await handleAskPermission(`${command} ${args.join(' ')}`)
  }
}

export async function checkWorkdirPermission(workdir: string): Promise<void> {
  if (!_directory) {
    return
  }

  const normalizedWorkdir = workdir.replace(/\/$/, '')
  const normalizedProject = _directory.replace(/\/$/, '')

  if (normalizedWorkdir.startsWith(normalizedProject)) {
    return
  }

  const config = await getPermissionConfig()
  const extDirPerm = config.external_directory

  if (extDirPerm === 'deny') {
    await denyWithToast(
      `PTY spawn denied: Working directory "${workdir}" is outside project directory "${_directory}". External directory access is denied by user configuration.`
    )
  }

  if (extDirPerm === 'ask') {
    // TODO: Implement user prompt for external directory access
  }
}

import { RingBuffer } from './buffer.ts'
import type { PTYSession, PTYSessionInfo, SpawnOptions } from './types.ts'
import { DEFAULT_TERMINAL_COLS, DEFAULT_TERMINAL_ROWS } from '../constants.ts'
import { existsSync } from 'node:fs'

// ── Lazy bun-pty import ─────────────────────────────────────────────────────
// bun-pty is a Bun-native module. Static imports crash the whole module graph
// if the native addon isn't available. We lazy-load at first spawn instead.
let _bunPtySpawn: ((...args: any[]) => any) | null = null
let _bunPtyLoadAttempted = false
let _bunPtyError: string | null = null

async function getBunPtySpawn(): Promise<(...args: any[]) => any> {
  if (_bunPtySpawn) return _bunPtySpawn

  if (_bunPtyLoadAttempted) {
    throw new Error(
      `[PTY spawn] bun-pty previously failed to load: ${_bunPtyError}. ` +
        `Cannot spawn PTY sessions. Fix the underlying issue and restart.`
    )
  }

  _bunPtyLoadAttempted = true
  try {
    const mod = await import('bun-pty') as any
    _bunPtySpawn = mod.spawn ?? mod.default?.spawn
    if (!_bunPtySpawn) {
      throw new Error(`bun-pty module loaded but 'spawn' export not found. Exports: ${Object.keys(mod).join(', ')}`)
    }
    return _bunPtySpawn
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err)
    _bunPtyError = msg
    throw new Error(
      `[PTY spawn] Failed to load bun-pty native module.\n` +
        `  Error: ${msg}\n` +
        `  Platform: ${process.platform}/${process.arch}\n` +
        `  Runtime: ${typeof Bun !== 'undefined' ? `Bun ${(Bun as any).version}` : 'NOT Bun (bun-pty requires Bun!)'}\n` +
        `  Fix: cd plugin/opencode-pty && bun install`
    )
  }
}

// ── Session lifecycle ───────────────────────────────────────────────────────
const SESSION_ID_BYTE_LENGTH = 4

function generateId(): string {
  const hex = Array.from(crypto.getRandomValues(new Uint8Array(SESSION_ID_BYTE_LENGTH)))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
  return `pty_${hex}`
}

export class SessionLifecycleManager {
  private sessions: Map<string, PTYSession> = new Map()

  private createSessionObject(opts: SpawnOptions): PTYSession {
    const id = generateId()
    const args = opts.args ?? []
    const workdir = opts.workdir ?? process.cwd()
    const title =
      opts.title ?? (`${opts.command} ${args.join(' ')}`.trim() || `Terminal ${id.slice(-4)}`)

    const buffer = new RingBuffer()
    return {
      id,
      title,
      description: opts.description,
      command: opts.command,
      args,
      workdir,
      env: opts.env,
      status: 'running',
      pid: 0, // will be set after spawn
      createdAt: new Date().toISOString(),
      parentSessionId: opts.parentSessionId,
      parentAgent: opts.parentAgent,
      notifyOnExit: opts.notifyOnExit ?? false,
      buffer,
      process: null, // will be set
    }
  }

  private async spawnProcess(session: PTYSession): Promise<void> {
    // Pre-flight checks with actionable diagnostics
    if (!session.command) {
      throw new Error(`[PTY spawn] command is empty/undefined. Provide a valid command.`)
    }

    if (session.workdir && !existsSync(session.workdir)) {
      throw new Error(
        `[PTY spawn] workdir does not exist: "${session.workdir}". ` +
          `Create the directory first or omit workdir to use cwd.`
      )
    }

    const env = { ...process.env, ...session.env } as Record<string, string>
    const spawnContext = {
      command: session.command,
      args: session.args,
      workdir: session.workdir,
      envKeys: session.env ? Object.keys(session.env) : [],
      cols: DEFAULT_TERMINAL_COLS,
      rows: DEFAULT_TERMINAL_ROWS,
    }

    // Lazy-load bun-pty spawn
    const bunPtySpawn = await getBunPtySpawn()

    try {
      const ptyProcess = bunPtySpawn(session.command, session.args, {
        name: 'xterm-256color',
        cols: DEFAULT_TERMINAL_COLS,
        rows: DEFAULT_TERMINAL_ROWS,
        cwd: session.workdir,
        env,
      })
      session.process = ptyProcess
      session.pid = ptyProcess.pid
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err)
      const stack = err instanceof Error ? err.stack : undefined

      // Classify the error for actionable diagnostics
      let hint = ''
      if (msg.includes('ENOENT') || msg.includes('not found')) {
        hint = `Command "${session.command}" not found. Is it installed and on PATH?`
      } else if (msg.includes('EACCES') || msg.includes('permission')) {
        hint = `Permission denied running "${session.command}". Check file permissions.`
      } else if (msg.includes('EIO') || msg.includes('pty') || msg.includes('openpty')) {
        hint = `PTY allocation failed at OS level. Max PTYs reached? Check: sysctl kern.tty.ptmx_max (macOS) or /proc/sys/kernel/pty/max (Linux).`
      } else if (msg.includes('bun-pty') || msg.includes('native') || msg.includes('dlopen')) {
        hint = `bun-pty native module failed to load. Was it compiled for this platform? Try: cd opencode-pty && bun install`
      }

      const diagnostics = [
        `[PTY spawn FAILED]`,
        `  Error: ${msg}`,
        hint ? `  Hint: ${hint}` : null,
        `  Context: ${JSON.stringify(spawnContext)}`,
        stack ? `  Stack: ${stack.split('\n').slice(0, 5).join('\n    ')}` : null,
      ]
        .filter(Boolean)
        .join('\n')

      console.error(diagnostics)
      throw new Error(diagnostics)
    }
  }

  private setupEventHandlers(
    session: PTYSession,
    onData: (session: PTYSession, data: string) => void,
    onExit: (session: PTYSession, exitCode: number | null) => void
  ): void {
    session.process?.onData((data: string) => {
      session.buffer.append(data)
      onData(session, data)
    })

    session.process?.onExit(({ exitCode, signal }) => {
      // Flush any remaining incomplete line in the buffer
      session.buffer.flush()

      if (session.status === 'killing') {
        session.status = 'killed'
      } else {
        session.status = 'exited'
      }
      session.exitCode = exitCode
      session.exitSignal = signal
      onExit(session, exitCode)
    })
  }

  async spawn(
    opts: SpawnOptions,
    onData: (session: PTYSession, data: string) => void,
    onExit: (session: PTYSession, exitCode: number | null) => void
  ): Promise<PTYSessionInfo> {
    const session = this.createSessionObject(opts)
    await this.spawnProcess(session)
    this.setupEventHandlers(session, onData, onExit)
    this.sessions.set(session.id, session)
    return this.toInfo(session)
  }

  kill(id: string, cleanup: boolean = false): boolean {
    const session = this.sessions.get(id)
    if (!session) {
      return false
    }

    if (session.status === 'running') {
      session.status = 'killing'
      try {
        session.process?.kill()
      } catch {
        // Ignore kill errors
      }
    }

    if (cleanup) {
      session.buffer.clear()
      this.sessions.delete(id)
    }

    return true
  }

  private clearAllSessionsInternal(): void {
    for (const id of [...this.sessions.keys()]) {
      this.kill(id, true)
    }
  }

  clearAllSessions(): void {
    this.clearAllSessionsInternal()
  }

  cleanupBySession(parentSessionId: string): void {
    for (const [id, session] of this.sessions) {
      if (session.parentSessionId === parentSessionId) {
        this.kill(id, true)
      }
    }
  }

  getSession(id: string): PTYSession | null {
    return this.sessions.get(id) || null
  }

  listSessions(): PTYSession[] {
    return Array.from(this.sessions.values())
  }

  toInfo(session: PTYSession): PTYSessionInfo {
    return {
      id: session.id,
      title: session.title,
      description: session.description,
      command: session.command,
      args: session.args,
      workdir: session.workdir,
      status: session.status,
      exitCode: session.exitCode,
      exitSignal: session.exitSignal,
      pid: session.pid,
      createdAt: session.createdAt,
      lineCount: session.buffer.length,
    }
  }
}

export function match(str: string, pattern: string): boolean {
  const regex = new RegExp(
    '^' +
      pattern
        .replace(/[.+^${}()|[\]\\]/g, '\\$&')
        .replace(/\*/g, '.*')
        .replace(/\?/g, '.') +
      '$',
    's'
  )
  return regex.test(str)
}

export function all(input: string, patterns: Record<string, string>): string | undefined {
  const sorted = Object.entries(patterns).sort(
    (a, b) => a[0].length - b[0].length || a[0].localeCompare(b[0])
  )
  let result: string | undefined
  for (const [pattern, value] of sorted) {
    if (match(input, pattern)) {
      result = value
    }
  }
  return result
}

export function allStructured(
  input: { head: string; tail: string[] },
  patterns: Record<string, string>
): string | undefined {
  const sorted = Object.entries(patterns).sort(
    (a, b) => a[0].length - b[0].length || a[0].localeCompare(b[0])
  )
  let result: string | undefined
  for (const [pattern, value] of sorted) {
    const parts = pattern.split(/\s+/)
    const firstPart = parts[0]
    if (!firstPart || !match(input.head, firstPart)) continue
    if (parts.length === 1 || matchSequence(input.tail, parts.slice(1))) {
      result = value
    }
  }
  return result
}

function matchSequence(items: string[], patterns: string[]): boolean {
  if (patterns.length === 0) return true
  const [pattern, ...rest] = patterns
  if (pattern === '*') return matchSequence(items, rest)
  for (let i = 0; i < items.length; i++) {
    const item = items[i]
    if (
      item !== undefined &&
      pattern !== undefined &&
      match(item, pattern) &&
      matchSequence(items.slice(i + 1), rest)
    ) {
      return true
    }
  }
  return false
}

// Shared constants used across the entire application
export const DEFAULT_READ_LIMIT = 500
export const MAX_LINE_LENGTH = 2000
export const DEFAULT_MAX_BUFFER_LINES = 50000

// Performance monitoring constants
export const PERFORMANCE_MEASURE_LIMIT = 100

import { type Plugin, tool } from '@opencode-ai/plugin'
import { DEFAULT_READ_LIMIT, MAX_LINE_LENGTH } from './opencode-pty/src/shared/constants.ts'
import { formatLine, formatSessionInfo } from './opencode-pty/src/plugin/pty/formatters.ts'
import { initPermissions, checkCommandPermission, checkWorkdirPermission } from './opencode-pty/src/plugin/pty/permissions.ts'
import { initManager, manager } from './opencode-pty/src/plugin/pty/manager.ts'

const ETX = String.fromCharCode(3)
const EOT = String.fromCharCode(4)

function notFound(id: string): Error {
  return new Error(`PTY session '${id}' not found. Use pty_list to see active sessions.`)
}

function parseEscapeSequences(input: string): string {
  return input.replace(/\\(x[0-9A-Fa-f]{2}|u[0-9A-Fa-f]{4}|[nrt\\])/g, (match, seq: string) => {
    if (seq.startsWith('x')) return String.fromCharCode(parseInt(seq.slice(1), 16))
    if (seq.startsWith('u')) return String.fromCharCode(parseInt(seq.slice(1), 16))
    switch (seq) {
      case 'n': return '\n'
      case 'r': return '\r'
      case 't': return '\t'
      case '\\': return '\\'
      default: return match
    }
  })
}

function extractCommands(data: string): string[] {
  return data
    .split(/[\n\r]+/)
    .map((line) => line.trim())
    .filter((line) => line && !line.startsWith(ETX) && !line.startsWith(EOT))
}

function parseCommand(commandLine: string): { command: string; args: string[] } {
  const parts = commandLine.split(/\s+/).filter(Boolean)
  return { command: parts[0] ?? '', args: parts.slice(1) }
}

function validateRegex(pattern: string): boolean {
  try {
    new RegExp(pattern)
    const dangerousPatterns = [
      /\(\?:.*\)\*.*\(\?:.*\)\*/,
      /.*\(\.\*\?\)\{2,\}.*/,
      /.*\(.*\|.*\)\{3,\}.*/,
    ]
    return !dangerousPatterns.some((dangerous) => dangerous.test(pattern))
  } catch {
    return false
  }
}

function buildPtyOutput(
  id: string,
  status: string,
  lines: string[],
  footer: string,
  pattern?: string,
): string {
  const inner = [
    `<pty_output id="${id}" status="${status}"${pattern ? ` pattern="${pattern}"` : ''}>`,
    ...lines,
    '',
    footer,
    `</pty_output>`,
  ].join('\n')
  return `<kortix_system type="pty-output" source="opencode-pty">\n${inner}\n</kortix_system>`
}

function escapeXml(text: string): string {
  return text
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
}

function errorMessage(err: unknown): string {
  return err instanceof Error ? err.message : String(err)
}

function buildPtyFailure(type: string, err: unknown): string {
  const message = escapeXml(errorMessage(err))
  return `<kortix_system type="${type}" source="opencode-pty">\n<pty_failed>\n${message}\n</pty_failed>\n</kortix_system>`
}

async function recoverPtyTool(type: string, action: () => Promise<string>): Promise<string> {
  try {
    return await action()
  } catch (err) {
    console.warn(`[pty-tools] ${type} failed: ${errorMessage(err)}`)
    return buildPtyFailure(type, err)
  }
}

const PtyToolsPlugin: Plugin = async ({ client, directory, serverUrl }) => {
  console.log('[pty-tools] plugin init')
  initPermissions(client, directory)
  initManager(client, serverUrl, directory)
  manager.probe().catch(() => undefined)

  return {
    tool: {
      pty_spawn: tool({
        description: 'Spawn a background PTY session for a long-running or interactive command.',
        args: {
          command: tool.schema.string().describe('Command/executable to run'),
          args: tool.schema.array(tool.schema.string()).optional().describe('Arguments to pass to the command'),
          workdir: tool.schema.string().optional().describe('Working directory for the PTY session'),
          env: tool.schema.object({}).catchall(tool.schema.string()).optional().describe('Additional environment variables'),
          title: tool.schema.string().optional().describe('Human-readable title for the session'),
          description: tool.schema.string().describe('Clear, concise 5-10 word description'),
          notifyOnExit: tool.schema.boolean().optional().describe('Notify when the process exits'),
        },
        async execute(args, ctx) {
          return recoverPtyTool('pty-spawn', async () => {
            await checkCommandPermission(args.command, args.args ?? [])
            if (args.workdir) await checkWorkdirPermission(args.workdir)
            const info = await manager.spawn({
              command: args.command,
              args: args.args,
              workdir: args.workdir,
              env: args.env,
              title: args.title,
              description: args.description,
              parentSessionId: ctx.sessionID,
              parentAgent: ctx.agent,
              notifyOnExit: args.notifyOnExit,
            })
            const inner = [
              'ID: ' + info.id,
              'Title: ' + info.title,
              `Command: ${info.command} ${info.args.join(' ')}`,
              'Workdir: ' + info.workdir,
              'PID: ' + info.pid,
              'Status: ' + info.status,
            ].join('\n')
            return `<kortix_system type="pty-spawn" source="opencode-pty">\n<pty_spawned>\n${inner}\n</pty_spawned>\n</kortix_system>`
          })
        },
      }),

      pty_write: tool({
        description: 'Send input to a running PTY session.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          data: tool.schema.string().describe('Input data to send to the PTY'),
        },
        async execute(args) {
          return recoverPtyTool('pty-write', async () => {
            const session = manager.get(args.id)
            if (!session) throw notFound(args.id)
            if (session.status !== 'running') {
              throw new Error(`Cannot write to PTY '${args.id}' - session status is '${session.status}'.`)
            }
            const parsedData = parseEscapeSequences(args.data)
            for (const commandLine of extractCommands(parsedData)) {
              const { command, args: cmdArgs } = parseCommand(commandLine)
              if (command) await checkCommandPermission(command, cmdArgs)
            }
            const success = await manager.write(args.id, parsedData)
            if (!success) throw new Error(`Failed to write to PTY '${args.id}'.`)
            const preview = args.data.length > 50 ? `${args.data.slice(0, 50)}...` : args.data
            const displayPreview = preview
              .replace(new RegExp(ETX, 'g'), '^C')
              .replace(new RegExp(EOT, 'g'), '^D')
              .replace(/\n/g, '\\n')
              .replace(/\r/g, '\\r')
            return `<kortix_system type="pty-write" source="opencode-pty">\nSent ${args.data.length} bytes to ${args.id}: "${displayPreview}"\n</kortix_system>`
          })
        },
      }),

      pty_read: tool({
        description: 'Read PTY output with pagination and optional regex filtering.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          offset: tool.schema.number().optional().describe('0-based starting line/match offset'),
          limit: tool.schema.number().optional().describe('Maximum number of lines/matches to return'),
          pattern: tool.schema.string().optional().describe('Regex filter applied before pagination'),
          ignoreCase: tool.schema.boolean().optional().describe('Case-insensitive regex matching'),
        },
        async execute(args) {
          return recoverPtyTool('pty-output', async () => {
            const session = manager.get(args.id)
            if (!session) throw notFound(args.id)
            const offset = args.offset ?? 0
            const limit = args.limit ?? DEFAULT_READ_LIMIT

            if (args.pattern) {
              if (!validateRegex(args.pattern)) {
                throw new Error(`Potentially dangerous regex pattern rejected: '${args.pattern}'. Please use a safer pattern.`)
              }
              const regex = new RegExp(args.pattern, args.ignoreCase ? 'i' : '')
              const result = manager.search(args.id, regex, offset, limit)
              if (!result) throw notFound(args.id)
              if (result.matches.length === 0) {
                return `<kortix_system type="pty-output" source="opencode-pty">\n<pty_output id="${args.id}" status="${session.status}" pattern="${args.pattern}">\nNo lines matched the pattern '${args.pattern}'.\nTotal lines in buffer: ${result.totalLines}\n</pty_output>\n</kortix_system>`
              }
              const lines = result.matches.map((match) => formatLine(match.text, match.lineNumber, MAX_LINE_LENGTH))
              const footer = result.hasMore
                ? `(${result.matches.length} of ${result.totalMatches} matches shown. Use offset=${offset + result.matches.length} to see more.)`
                : `(${result.totalMatches} match${result.totalMatches === 1 ? '' : 'es'} from ${result.totalLines} total lines)`
              return buildPtyOutput(args.id, session.status, lines, footer, args.pattern)
            }

            const result = manager.read(args.id, offset, limit)
            if (!result) throw notFound(args.id)
            if (result.lines.length === 0) {
              return `<kortix_system type="pty-output" source="opencode-pty">\n<pty_output id="${args.id}" status="${session.status}">\n(No output available - buffer is empty)\nTotal lines: ${result.totalLines}\n</pty_output>\n</kortix_system>`
            }
            const lines = result.lines.map((line, index) => formatLine(line, result.offset + index + 1, MAX_LINE_LENGTH))
            const footer = result.hasMore
              ? `(Buffer has more lines. Use offset=${result.offset + result.lines.length} to read beyond line ${result.offset + result.lines.length})`
              : `(End of buffer - total ${result.totalLines} lines)`
            return buildPtyOutput(args.id, session.status, lines, footer)
          })
        },
      }),

      pty_list: tool({
        description: 'List active PTY sessions.',
        args: {},
        async execute() {
          return recoverPtyTool('pty-list', async () => {
            const sessions = await manager.list()
            if (sessions.length === 0) {
              return `<kortix_system type="pty-list" source="opencode-pty">\n<pty_list>\nNo active PTY sessions.\n</pty_list>\n</kortix_system>`
            }
            const inner = ['<pty_list>', ...sessions.flatMap((session) => formatSessionInfo(session)), `Total: ${sessions.length} session(s)`, '</pty_list>'].join('\n')
            return `<kortix_system type="pty-list" source="opencode-pty">\n${inner}\n</kortix_system>`
          })
        },
      }),

      pty_kill: tool({
        description: 'Terminate a PTY session and optionally clean it up.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          cleanup: tool.schema.boolean().optional().describe('If true, remove the cached session data too'),
        },
        async execute(args) {
          return recoverPtyTool('pty-kill', async () => {
            const session = manager.get(args.id)
            if (!session) throw notFound(args.id)
            const wasRunning = session.status === 'running'
            const cleanup = args.cleanup ?? false
            const success = await manager.kill(args.id, cleanup)
            if (!success) throw new Error(`Failed to kill PTY session '${args.id}'.`)
            const action = wasRunning ? 'Killed' : 'Cleaned up'
            const cleanupNote = cleanup ? ' (session removed)' : ' (session retained for log access)'
            const inner = [
              '<pty_killed>',
              `${action}: ${args.id}${cleanupNote}`,
              `Title: ${session.title}`,
              `Command: ${session.command} ${session.args.join(' ')}`,
              `Final line count: ${session.lineCount}`,
              '</pty_killed>',
            ].join('\n')
            return `<kortix_system type="pty-kill" source="opencode-pty">\n${inner}\n</kortix_system>`
          })
        },
      }),
    },
    event: async ({ event }) => {
      if (event.type === 'session.deleted') manager.cleanupBySession(event.properties.info.id)
    },
  }
}

