          "E.g. 'python', 'typescript', 'rust', 'json', 'bash'.",
      ),

    metadata: tool.schema
      .string()
      .optional()
      .describe(
        "Optional JSON string of extra metadata. E.g. '{\"width\":1024,\"format\":\"png\",\"duration\":\"3:42\"}'.",
      ),

