      let parsed: unknown;
      try {
        parsed = typeof args.items === "string" ? JSON.parse(args.items) : args.items;
      } catch {
        return `Error: Invalid JSON in 'items' parameter. Must be a JSON array of objects.`;
      }

      if (!Array.isArray(parsed) || parsed.length === 0) {
        return `Error: 'items' must be a non-empty JSON array.`;
      }

      const entries: ShowEntry[] = [];
      const errors: string[] = [];

      for (let i = 0; i < parsed.length; i++) {
        const item = parsed[i];
        if (!item || typeof item !== "object") {
          errors.push(`Item ${i}: must be an object.`);
          continue;
        }
        const result = validateAndBuildEntry(item as Record<string, unknown>);
        if (typeof result === "string") {
          errors.push(`Item ${i}: ${result}`);
        } else {
          entries.push(result);
        }
      }

      if (errors.length > 0 && entries.length === 0) {
        return `Error: All items failed validation:\n${errors.join("\n")}`;
      }

      const titleLabel = args.title || `${entries.length} items`;

      return JSON.stringify(
        {
          success: true,
          action: "show",
          ...(args.title && { title: args.title }),
          ...(args.description && { description: args.description }),
          ...(args.theme && args.theme !== "default" && { theme: args.theme }),
          items: entries,
          ...(errors.length > 0 && { warnings: errors }),
          message: `${entries.length} item(s) presented to user as carousel.`,
        },
        null,
        2,
      );
    }

    // ── Single-item mode (type is provided directly) ──
    const type = args.type as ShowType | undefined;
    if (!type || !TYPES.includes(type as ShowType)) {
      return `Error: 'type' is required for 'show' action. Use one of: ${TYPES.join(", ")}. Or pass 'items' for multi-item carousel.`;
    }

    const result = validateAndBuildEntry(args);
    if (typeof result === "string") return result;

    return JSON.stringify(
      {
        success: true,
        action: "show",
        entry: result,
        message: `Item '${args.title || type}' presented to user.`,
      },
      null,
      2,
    );
  },
});

import { tool } from "@opencode-ai/plugin";
import { getEnv, getKortixRouterBase } from "./lib/get-env";
// NOTE: @tavily/core is imported lazily inside execute() — a top-level import
// makes opencode load this heavy SDK at sandbox boot (every tool module is
// evaluated eagerly), which added ~seconds to cold session start. Deferring it
// to first use keeps boot fast and only pays the cost when the tool is run.

interface SearchResult {
  title: string;
  url: string;
  content: string;
  score: number;
  publishedDate?: string;
  rawContent?: string;
}

interface SearchImage {
  url: string;
  description?: string;
}

interface SearchResponse {
  query: string;
  answer?: string;
  results: SearchResult[];
  images?: SearchImage[];
  responseTime?: number;
}

function formatSingle(query: string, response: SearchResponse): string {
  return JSON.stringify(
    {
      query,
      success: response.results.length > 0 || !!response.answer,
      answer: response.answer ?? "",
      results: response.results.map((r) => ({
        title: r.title,
        url: r.url,
        snippet: r.content,
        score: r.score,
        published_date: r.publishedDate ?? "",
      })),
      images: (response.images ?? []).map((img) => ({
        url: img.url,
        description: img.description ?? "",
      })),
      response_time_ms: response.responseTime,
    },
    null,
    2,
  );
}

export default tool({
  description:
    "Search the web for up-to-date information using Tavily. " +
    "Returns titles, URLs, snippets, relevance scores, images, and a synthesized AI answer. " +
    "Supports batch queries separated by |||. " +
    "Use topic='news' for current events, topic='finance' for financial data. " +
    "After using results, ALWAYS include a Sources section with markdown hyperlinks.",
  args: {
    query: tool.schema
      .string()
      .describe(
        "Search query. For batch, separate with ||| (e.g. 'query one ||| query two')",
      ),
    num_results: tool.schema
      .number()
      .optional()
      .describe("Results per query (1-20). Default: 5"),
    topic: tool.schema
      .string()
      .optional()
      .describe("Search topic: 'general' (default), 'news', or 'finance'"),
    search_depth: tool.schema
      .string()
      .optional()
      .describe(
        "Search depth: 'basic' (faster, cheaper, default) or 'advanced' (slower, more thorough). Use 'basic' for most queries. Reserve 'advanced' for deep research where comprehensiveness matters.",
      ),
  },
  async execute(args, _context) {
    // Route through the Kortix router (derived from KORTIX_API_URL) and auth with
    // KORTIX_SANDBOX_TOKEN (KORTIX_TOKEN kept as a legacy fallback); the router
    // injects the real upstream key. Fall back to a raw TAVILY_API_KEY only when
    // KORTIX_API_URL is unset (self-host/direct).
    const apiBaseURL = getKortixRouterBase("tavily") ?? undefined;
    const apiKey = apiBaseURL
      ? getEnv("KORTIX_SANDBOX_TOKEN") || getEnv("KORTIX_TOKEN")
      : getEnv("TAVILY_API_KEY");
    if (!apiKey) return apiBaseURL
      ? "Error: KORTIX_SANDBOX_TOKEN not set."
      : "Error: TAVILY_API_KEY not set.";

    const { tavily } = await import("@tavily/core");
    const client = tavily({ apiKey, ...(apiBaseURL ? { apiBaseURL } : {}) });
    const maxResults = Math.max(1, Math.min(args.num_results ?? 5, 20));
    const topic = (args.topic as "general" | "news" | "finance") ?? "general";

    const queries = args.query
      .split("|||")
      .map((q) => q.trim())
      .filter(Boolean);
    if (queries.length === 0) return "Error: empty query.";

    const searchOne = async (
      q: string,
    ): Promise<{ query: string; data?: SearchResponse; error?: string }> => {
      try {
        const response = (await client.search(q, {
          searchDepth: (args.search_depth as "basic" | "advanced") || "basic",
          topic,
          maxResults,
          includeAnswer: true,
          includeImages: true,
          includeImageDescriptions: true,
        })) as unknown as SearchResponse;
        return { query: q, data: response };
      } catch (e) {
        return { query: q, error: String(e) };
      }
    };

    const results = await Promise.all(queries.map(searchOne));

    if (queries.length === 1) {
      const r = results[0]!;
      if (r.error)
        return JSON.stringify(
          { query: r.query, success: false, error: r.error },
          null,
          2,
        );
      return formatSingle(r.query, r.data!);
    }

    return JSON.stringify(
      {
        batch_mode: true,
        total_queries: queries.length,
        results: results.map((r) => {
          if (r.error)
            return { query: r.query, success: false, error: r.error };
          const d = r.data!;
          return {
            query: r.query,
            success: d.results.length > 0 || !!d.answer,
            answer: d.answer ?? "",
            results: d.results.map((res) => ({
              title: res.title,
              url: res.url,
              snippet: res.content,
              score: res.score,
              published_date: res.publishedDate ?? "",
            })),
            images: (d.images ?? []).map((img) => ({
              url: img.url,
              description: img.description ?? "",
            })),
          };
        }),
      },
      null,
      2,
    );
  },
});

#!/usr/bin/env python3
"""Annotate an XLSX with review issues as cell comments.

Usage:
    python annotate_xlsx.py input.xlsx output.xlsx

Reads issues from document_review_state.json in the working directory.
Uses openpyxl Comments attached to cells containing the
original text. Falls back to cell A1 if text not found.
"""

import json
import shutil
import sys
from pathlib import Path

from constants import STATE_FILENAME
from models import format_comment
from openpyxl import load_workbook
from openpyxl.comments import Comment

AUTHOR = "Kortix"


def load_issues():
    """Load issues from document_review_state.json."""
    path = Path(STATE_FILENAME)
    if not path.exists():
        print(
            f"Error: {STATE_FILENAME} not found.",
            file=sys.stderr,
        )
        sys.exit(1)
    state = json.loads(path.read_text(encoding="utf-8"))
    return list(state.get("issues", {}).values())


def find_cell(ws, text):
    """Find first cell containing the given text."""
    target = str(text).strip().lower()
    for row in ws.iter_rows():
        for cell in row:
            if cell.value is None:
                continue
            if target in str(cell.value).strip().lower():
                return cell
    return None


def find_worksheet(wb, location):
    """Find a worksheet by name (case-insensitive)."""
    for ws in wb.worksheets:
        if ws.title.lower() == location.lower():
            return ws
    return None


def _place_on_cell(ws, anchor, comment):
    """Try to place a comment directly on the given cell reference."""
    try:
        cell = ws[anchor]
        cell.comment = comment
        return True
    except (KeyError, ValueError):
        return False


def annotate(input_path, output_path):
    """Add comment annotations to the XLSX."""
    issues = load_issues()
    if not issues:
        print("No issues to annotate.")
        return

    shutil.copy2(input_path, output_path)
    wb = load_workbook(output_path)
    annotated = 0

    for issue in issues:
        text = format_comment(issue)
        comment = Comment(text, AUTHOR)
        original = issue.get("original_text", "")
        location = issue.get("location", "")
        anchor = issue.get("anchor")

        placed = False

        target_ws = find_worksheet(wb, location) if location else None

        if target_ws and anchor:
            placed = _place_on_cell(target_ws, anchor, comment)

        if not placed and target_ws:
            cell = find_cell(target_ws, original)
            if cell:
                cell.comment = comment
                placed = True

        if not placed:
            for ws in wb.worksheets:
                cell = find_cell(ws, original)
                if cell:
                    cell.comment = comment
                    placed = True
                    break

        if not placed:
            ws = wb.worksheets[0]
            fallback = ws["A1"]
            if fallback.comment:
                existing = fallback.comment.text
                fallback.comment = Comment(
                    f"{existing}\n\n---\n\n{text}",
                    AUTHOR,
                )
            else:
                fallback.comment = comment

        annotated += 1

    wb.save(output_path)
    print(f"Added {annotated} comments to {output_path}")


if __name__ == "__main__":
    if len(sys.argv) != 3:
        print(
            "Usage: annotate_xlsx.py <input.xlsx> <output.xlsx>",
            file=sys.stderr,
        )
        sys.exit(1)
    annotate(sys.argv[1], sys.argv[2])

# Generating Word Documents from Scratch

Use JavaScript and the `docx` module to build .docx files programmatically, then run the validator to catch structural issues.

## Workflow

1. **Initialize** -- load the library, set up the document skeleton
2. **Configure pages** -- dimensions, margins, portrait vs. landscape
3. **Define typography** -- heading overrides, body font defaults
4. **Assemble content** -- paragraphs, lists, tables, images, hyperlinks, tab stops, columns
5. **Export** -- write the buffer to disk, run validation

## Initialization

```javascript
const fs = require('fs');
const docx = require('docx');
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, Header, Footer, AlignmentType, PageOrientation, LevelFormat,
} = docx;
const {
  ExternalHyperlink, InternalHyperlink, Bookmark,
  TableOfContents, HeadingLevel,
  BorderStyle, WidthType, ShadingType, VerticalAlign, PageNumber,
  PageBreak, FootnoteReferenceRun,
} = docx;

const report = new Document({ sections: [{ children: [/* ... */] }] });
Packer.toBuffer(report).then(buf => fs.writeFileSync("deliverable.docx", buf));
```

Validation runs automatically when you share the file. If issues are reported, unpack the file, correct the XML, and repack (see EDITING.md).

## Page configuration

### Paper dimensions

The library defaults to A4 paper. When targeting US Letter, you must specify dimensions explicitly.

All measurements use DXA units (twentieths of a typographic point). One inch equals 1440 DXA.

| Format | Width (DXA) | Height (DXA) | Printable area with 1-inch margins |
|--------|-------------|---------------|-------------------------------------|
| US Letter | 12240 | 15840 | 9360 |
| A4 | 11906 | 16838 | 9026 |

```javascript
sections: [{
  properties: {
    page: {
      size: { width: 12240, height: 15840 },
      margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 }
    }
  },
  children: [/* ... */]
}]
```

### Landscape mode

The library performs an internal width/height swap for landscape pages. Supply the standard portrait values and set the orientation flag -- the engine handles the rest.

```javascript
size: {
  width: 12240,
  height: 15840,
  orientation: PageOrientation.LANDSCAPE
},
// Usable horizontal space in landscape = long edge minus both margins
// 15840 - 1440 - 1440 = 12960 DXA
```

## Typography and heading styles

Pick a professional, universally installed sans-serif font as your base. Check `skills/design-foundations/SKILL.md` for typeface recommendations. Keep heading text in black to ensure legibility.

Override the built-in heading style definitions by referencing their canonical IDs. The `outlineLevel` property is mandatory -- without it, Table of Contents generation will not pick up these headings.

```javascript
const report = new Document({
  styles: {
    default: { document: { run: { font: "Arial", size: 24 } } },
    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 36, bold: true, font: "Arial" },
        paragraph: { spacing: { before: 280, after: 140 }, outlineLevel: 0 } },
      { id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Arial" },
        paragraph: { spacing: { before: 220, after: 110 }, outlineLevel: 1 } },
    ]
  },
  sections: [{
    children: [
      new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun("Key Findings")] }),
    ]
  }]
});
```

## Lists

**Do not insert bullet characters directly** -- raw Unicode bullets (`\u2022`) will not produce proper list formatting in Word.

```javascript
const report = new Document({
  numbering: {
    config: [
      { reference: "bullets",
        levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
      { reference: "steps",
        levels: [{ level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
    ]
  },
  sections: [{
    children: [
      new Paragraph({ numbering: { reference: "bullets", level: 0 },
        children: [new TextRun("Key takeaway")] }),
      new Paragraph({ numbering: { reference: "steps", level: 0 },
        children: [new TextRun("First action")] }),
    ]
  }]
});
```

Numbering sequences: paragraphs sharing the same `reference` value form one continuous sequence (1, 2, 3 ... 4, 5, 6). Paragraphs using a different `reference` start a fresh sequence (1, 2, 3 ... 1, 2, 3).

## Tables

You must set widths in two places: on the table object and on every individual cell. Omitting either causes inconsistent rendering across platforms.

**Avoid `WidthType.PERCENTAGE`** -- Google Docs does not handle percentage-based table widths correctly. Stick to `WidthType.DXA`.

**Avoid `ShadingType.SOLID`** -- this fills cells completely black. Use `ShadingType.CLEAR` with a `fill` hex color.

```javascript
const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: "B0B0B0" };
const allBorders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

new Table({
  width: { size: 9360, type: WidthType.DXA },
  columnWidths: [5200, 4160],
  rows: [
    new TableRow({
      children: [
        new TableCell({
          borders: allBorders,
          width: { size: 5200, type: WidthType.DXA },
          shading: { fill: "EDF2F7", type: ShadingType.CLEAR },
          margins: { top: 60, bottom: 60, left: 100, right: 100 },
          children: [new Paragraph({ children: [new TextRun({ text: "Label", bold: true })] })]
        }),
        new TableCell({
          borders: allBorders,
          width: { size: 4160, type: WidthType.DXA },
          shading: { fill: "EDF2F7", type: ShadingType.CLEAR },
          margins: { top: 60, bottom: 60, left: 100, right: 100 },
          children: [new Paragraph({ children: [new TextRun({ text: "Amount", bold: true })] })]
        }),
      ]
    })
  ]
})
```

Sizing guidelines:
- The table `width` must equal the sum of all entries in `columnWidths`
- Each cell's `width` must correspond to its position in the `columnWidths` array
- Cell `margins` define internal padding -- they shrink the content area, not expand the cell
- For edge-to-edge tables: set table width to page width minus left and right margins

## Images

The `type` field is required on every `ImageRun`.

```javascript
new Paragraph({
  children: [new ImageRun({
    type: "png",
    data: fs.readFileSync("diagram.png"),
    transformation: { width: 350, height: 220 },
    altText: { title: "Monthly trend analysis", description: "Line chart of monthly active users Jan-Dec", name: "trend-chart" }
  })]
})
```

Accepted formats: `png`, `jpg`, `jpeg`, `gif`, `bmp`, `svg`

## Hyperlinks

### External links

```javascript
new Paragraph({
  children: [
    new TextRun("Refer to "),
    new ExternalHyperlink({
      children: [new TextRun({ text: "the project wiki", style: "Hyperlink" })],
      link: "https://wiki.example.org"
    }),
    new TextRun(" for background.")
  ]
})
```

### Internal cross-references (bookmarks)

```javascript
new Paragraph({
  children: [
    new Bookmark({ id: "section-data", children: [new TextRun("Data Collection Methods")] })
  ]
})

new Paragraph({
  children: [
    new TextRun("Details are in "),
    new InternalHyperlink({ anchor: "section-data",
      children: [new TextRun({ text: "Data Collection Methods", style: "Hyperlink" })] }),
    new TextRun(".")
  ]
})
```

## Page breaks

Insert a standalone break or trigger one before a specific paragraph. Either way, the break must live inside a `Paragraph` element -- placing it elsewhere produces malformed XML.

```javascript
new Paragraph({ children: [new PageBreak()] })

new Paragraph({ pageBreakBefore: true, children: [new TextRun("Next section begins here")] })
```

## Table of Contents

The TOC scans for paragraphs that use the `HeadingLevel` enum. Paragraphs styled with custom paragraph styles will not appear in the generated TOC, even if they visually resemble headings.

```javascript
new TableOfContents("Table of Contents", { hyperlink: true, headingStyleRange: "1-3" })
```

## Headers and footers

```javascript
sections: [{
  properties: {
    page: { margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 } }
  },
  headers: {
    default: new Header({ children: [
      new Paragraph({ alignment: AlignmentType.RIGHT,
        children: [new TextRun({ text: "Internal Use Only", italics: true, color: "999999", size: 16 })] })
    ] })
  },
  footers: {
    default: new Footer({ children: [
      new Paragraph({ alignment: AlignmentType.CENTER,
        children: [new TextRun("Page "), new TextRun({ children: [PageNumber.CURRENT] }),
                   new TextRun(" of "), new TextRun({ children: [PageNumber.TOTAL_PAGES] })] })
    ] })
  },
  children: [/* ... */]
}]
```

## Source citations

When content draws on external sources, attach numbered footnotes with clickable links so readers can verify claims.

```javascript
const report = new Document({
  footnotes: {
    1: { children: [new Paragraph({ children: [
      new TextRun("World Bank, Global Economic Prospects, "),
      new ExternalHyperlink({ children: [new TextRun({ text: "https://worldbank.org/en/publication/global-economic-prospects", style: "Hyperlink" })], link: "https://worldbank.org/en/publication/global-economic-prospects" })
    ]})] },
    2: { children: [new Paragraph({ children: [
      new TextRun("NOAA, Annual Climate Report, "),
      new ExternalHyperlink({ children: [new TextRun({ text: "https://ncei.noaa.gov/access/monitoring/monthly-report/global", style: "Hyperlink" })], link: "https://ncei.noaa.gov/access/monitoring/monthly-report/global" })
    ]})] },
  },
  sections: [{
    children: [
      new Paragraph({ children: [
        new TextRun("Emerging economies are projected to grow 4.2% this year"),
        new FootnoteReferenceRun(1),
        new TextRun(", as global average temperatures set another record"),
        new FootnoteReferenceRun(2),
        new TextRun(".")
      ] })
    ]
  }]
});
```

## Rules

- **Specify paper size** -- the library assumes A4 by default; set 12240 x 15840 DXA for US Letter
- **Supply portrait values for landscape** -- the engine swaps dimensions internally when `orientation: PageOrientation.LANDSCAPE` is set
- **Line breaks need separate Paragraphs** -- `\n` inside a TextRun does nothing useful
- **Bullet lists require numbering config** -- inserting raw Unicode bullet characters produces broken formatting
- **Wrap PageBreak in a Paragraph** -- a bare PageBreak generates invalid XML
- **Always declare `type` on ImageRun** -- the library cannot infer the image format
- **Use DXA for all table widths** -- `WidthType.PERCENTAGE` is unreliable in Google Docs
- **Set widths on both the table and each cell** -- the `columnWidths` array and individual cell `width` values must agree
- **Column widths must sum to the table width** -- any mismatch causes layout shifts
- **Include cell margins for readability** -- internal padding keeps text from pressing against borders
- **Apply `ShadingType.CLEAR` for cell backgrounds** -- `SOLID` fills cells with black
- **TOC only recognizes `HeadingLevel`** -- custom paragraph styles are invisible to the TOC generator
- **Reference canonical style IDs** -- use `"Heading1"`, `"Heading2"`, etc. to override built-in styles
- **Set `outlineLevel` on heading styles** -- the TOC needs this property (0 for H1, 1 for H2, and so on)

"""Extract a DOCX file into a directory of human-readable XML.

Pipeline: unzip → indent XML → coalesce tracked changes → merge runs → escape curly quotes.

Each post-processing step operates directly on document.xml in the output directory.
Run coalescing and merging can be disabled independently via CLI flags.

Usage:
    python unpack.py <docx_file> <output_dir>
    python unpack.py document.docx working/
    python unpack.py document.docx working/ --merge-runs false
    python unpack.py document.docx working/ --coalesce-changes false
"""

import re
import sys
import zipfile
from dataclasses import dataclass
from itertools import groupby
from pathlib import Path

from lxml import etree

WORDPROCESSINGML_NS = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
AUTHOR_ATTR = f"{{{WORDPROCESSINGML_NS}}}author"
TAG_RUN = f"{{{WORDPROCESSINGML_NS}}}r"
TAG_RPR = f"{{{WORDPROCESSINGML_NS}}}rPr"
TAG_TEXT = f"{{{WORDPROCESSINGML_NS}}}t"
TAG_PROOF_ERR = f"{{{WORDPROCESSINGML_NS}}}proofErr"
XML_SPACE_ATTR = "{http://www.w3.org/XML/1998/namespace}space"

CURLY_QUOTE_PATTERN = re.compile("[\u201c\u201d\u2018\u2019]")
CURLY_QUOTE_ENTITIES = {
    "\u201c": "&#x201C;",
    "\u201d": "&#x201D;",
    "\u2018": "&#x2018;",
    "\u2019": "&#x2019;",
}


@dataclass
class UnpackResult:
    xml_count: int
    runs_merged: int
    changes_coalesced: int


def unpack_docx(
    input_file: str,
    output_directory: str,
    merge_runs: bool = True,
    coalesce_changes: bool = True,
) -> tuple[UnpackResult | None, str]:
    src = Path(input_file)
    dst = Path(output_directory)

    if not src.exists():
        return None, f"Error: {input_file} does not exist"
    if src.suffix.lower() != ".docx":
        return None, f"Error: {input_file} is not a .docx file"

    try:
        dst.mkdir(parents=True, exist_ok=True)

        with zipfile.ZipFile(src, "r") as zf:
            zf.extractall(dst)

        xml_files = list(dst.rglob("*.xml")) + list(dst.rglob("*.rels"))
        for xf in xml_files:
            _indent_xml(xf)

        runs_merged = 0
        changes_coalesced = 0

        doc_xml = dst / "word" / "document.xml"
        if doc_xml.exists():
            if coalesce_changes:
                changes_coalesced = _coalesce_tracked_changes(doc_xml)
            if merge_runs:
                runs_merged = _merge_adjacent_runs(doc_xml)

        for xf in xml_files:
            _replace_curly_quotes(xf)

        parts = [f"Unpacked {input_file} ({len(xml_files)} XML files"]
        if changes_coalesced:
            parts.append(f"coalesced {changes_coalesced} tracked changes")
        if runs_merged:
            parts.append(f"merged {runs_merged} runs")
        summary = ", ".join(parts) + ")"

        return UnpackResult(len(xml_files), runs_merged, changes_coalesced), summary

    except zipfile.BadZipFile:
        return None, f"Error: {input_file} is not a valid ZIP archive"


def _indent_xml(xml_file: Path) -> None:
    try:
        tree = etree.parse(str(xml_file))
        etree.indent(tree, space="  ")
        xml_file.write_bytes(etree.tostring(tree, xml_declaration=True, encoding="UTF-8", pretty_print=True))
    except Exception:
        pass


def _replace_curly_quotes(xml_file: Path) -> None:
    try:
        raw = xml_file.read_text(encoding="utf-8")
        if not CURLY_QUOTE_PATTERN.search(raw):
            return
        xml_file.write_text(
            CURLY_QUOTE_PATTERN.sub(lambda m: CURLY_QUOTE_ENTITIES[m.group()], raw),
            encoding="utf-8",
        )
    except Exception:
        pass


# ---------------------------------------------------------------------------
# Run merging: consolidate adjacent <w:r> elements with identical <w:rPr>
# ---------------------------------------------------------------------------


def _merge_adjacent_runs(doc_xml: Path) -> int:
    if not doc_xml.exists():
        return 0
    tree = etree.parse(str(doc_xml))
    root = tree.getroot()

    for elem in list(root.iter(TAG_PROOF_ERR)):
        elem.getparent().remove(elem)

    for run in root.iter(TAG_RUN):
        for k in [a for a in run.attrib if "rsid" in a.lower()]:
            del run.attrib[k]

    seen: set[int] = set()
    containers: list[etree._Element] = []
    for run in root.iter(TAG_RUN):
        parent = run.getparent()
        pid = id(parent)
        if pid not in seen:
            seen.add(pid)
            containers.append(parent)

    total = sum(_merge_runs_in(c) for c in containers)
    if total > 0:
        doc_xml.write_bytes(etree.tostring(tree, xml_declaration=True, encoding="UTF-8", standalone=True))
    return total


def _canonical_rpr(run_elem: etree._Element) -> str | None:
    rpr = run_elem.find(TAG_RPR)
    if rpr is None:
        return None
    return etree.tostring(rpr, method="c14n2").decode()


def _merge_runs_in(container: etree._Element) -> int:
    groups: list[list[etree._Element]] = []
    active: list[etree._Element] = []
    active_sig: str | None = None

    for child in container:
        if child.tag != TAG_RUN:
            if active:
                groups.append(active)
                active = []
                active_sig = None
            continue
        sig = _canonical_rpr(child)
        if active and sig == active_sig:
            active.append(child)
        else:
            if active:
                groups.append(active)
            active = [child]
            active_sig = sig
    if active:
        groups.append(active)

    absorbed = 0
    for group in groups:
        if len(group) < 2:
            continue
        anchor = group[0]
        for donor in group[1:]:
            for node in list(donor):
                if node.tag != TAG_RPR:
                    anchor.append(node)
            container.remove(donor)
            absorbed += 1
        _join_adjacent_text(anchor)
    return absorbed


def _join_adjacent_text(run: etree._Element) -> None:
    children = list(run)
    idx = 0
    while idx < len(children) - 1:
        cur, nxt = children[idx], children[idx + 1]
        if cur.tag == TAG_TEXT and nxt.tag == TAG_TEXT:
            merged = (cur.text or "") + (nxt.text or "")
            cur.text = merged
            if merged.startswith(" ") or merged.endswith(" "):
                cur.set(XML_SPACE_ATTR, "preserve")
            elif XML_SPACE_ATTR in cur.attrib:
                del cur.attrib[XML_SPACE_ATTR]
            run.remove(nxt)
            children.pop(idx + 1)
        else:
            idx += 1


# ---------------------------------------------------------------------------
# Tracked-change coalescing: merge adjacent ins/del from the same author
# ---------------------------------------------------------------------------


def _coalesce_tracked_changes(doc_xml: Path) -> int:
    if not doc_xml.exists():
        return 0
    raw = doc_xml.read_bytes()
    root = etree.fromstring(raw, parser=etree.XMLParser(remove_blank_text=False))

    p_xpath = f".//{{{WORDPROCESSINGML_NS}}}p"
    tc_xpath = f".//{{{WORDPROCESSINGML_NS}}}tc"
    containers = root.findall(p_xpath) + root.findall(tc_xpath)

    reduction = 0
    for container in containers:
        for change_type in ("ins", "del"):
            reduction += _coalesce_in(container, change_type)

    if reduction > 0:
        doc_xml.write_bytes(etree.tostring(root, xml_declaration=True, encoding="UTF-8"))
    return reduction


def _coalesce_in(container: etree._Element, change_type: str) -> int:
    tag = f"{{{WORDPROCESSINGML_NS}}}{change_type}"
    matching = [ch for ch in container if ch.tag == tag]
    if len(matching) < 2:
        return 0

    total = 0
    for _author, run_iter in groupby(matching, key=lambda e: e.get(AUTHOR_ATTR, "")):
        total += _merge_change_run(list(run_iter))
    return total


def _merge_change_run(elements: list[etree._Element]) -> int:
    if len(elements) < 2:
        return 0
    absorbed = 0
    anchor = elements[0]
    for later in elements[1:]:
        if _changes_adjacent(anchor, later):
            for child in list(later):
                anchor.append(child)
            parent = later.getparent()
            if parent is not None:
                if later.tail:
                    prev = later.getprevious()
                    if prev is not None:
                        prev.tail = (prev.tail or "") + later.tail
                    else:
                        parent.text = (parent.text or "") + later.tail
                parent.remove(later)
            absorbed += 1
        else:
            anchor = later
    return absorbed


def _changes_adjacent(a: etree._Element, b: etree._Element) -> bool:
    parent = a.getparent()
    if parent is None:
        return False
    children = list(parent)
    try:
        pos_a, pos_b = children.index(a), children.index(b)
    except ValueError:
        return False
    text_between = a.tail or ""
    for mid in children[pos_a + 1 : pos_b]:
        if mid.tag is not etree.Comment:
            return False
        text_between += mid.tail or ""
    return text_between.strip() == ""


if __name__ == "__main__":
    import argparse

    ap = argparse.ArgumentParser(description="Unpack a DOCX file for XML editing")
    ap.add_argument("input_file", help="DOCX file to unpack")
    ap.add_argument("output_directory", help="Destination directory")
    ap.add_argument(
        "--merge-runs",
        type=lambda x: x.lower() == "true",
        default=True,
        metavar="true|false",
        help="Merge adjacent runs with identical formatting (default: true)",
    )
    ap.add_argument(
        "--coalesce-changes",
        type=lambda x: x.lower() == "true",
        default=True,
        metavar="true|false",
        help="Coalesce consecutive tracked changes from same author (default: true)",
    )
    args = ap.parse_args()

    _, message = unpack_docx(
        args.input_file,
        args.output_directory,
        merge_runs=args.merge_runs,
        coalesce_changes=args.coalesce_changes,
    )
    print(message)
    if "Error" in message:
        sys.exit(1)

"""Native fillable PDF field operations.

Usage:
    python formfill.py detect <file.pdf>
    python formfill.py extract <input.pdf> <output.json>
    python formfill.py fill <input.pdf> <values.json> <output.pdf>
"""

import json
import sys
from dataclasses import dataclass, field
from pathlib import Path

from pypdf import PdfReader, PdfWriter


@dataclass
class FormField:
    name: str
    kind: str
    page: int = 0
    rect: list[float] | None = None


@dataclass
class CheckboxField(FormField):
    on_value: str = ""
    off_value: str = "/Off"


@dataclass
class RadioGroup(FormField):
    options: list[dict[str, object]] = field(default_factory=list)


@dataclass
class ChoiceField(FormField):
    choices: list[dict[str, str]] = field(default_factory=list)


def _has_orphaned_widgets(reader: PdfReader) -> bool:
    for page in reader.pages:
        annots = page.get("/Annots")
        if not annots:
            continue
        for ann in annots:
            resolved = ann.get_object() if hasattr(ann, "get_object") else ann
            if resolved.get("/Subtype") == "/Widget" and resolved.get("/FT"):
                return True
    return False


def _full_field_name(annotation: dict) -> str | None:
    parts: list[str] = []
    node = annotation
    while node:
        t = node.get("/T")
        if t:
            parts.append(t)
        node = node.get("/Parent")
    return ".".join(reversed(parts)) if parts else None


def _build_field_from_dict(raw: dict, name: str) -> FormField:
    ft = raw.get("/FT")
    match ft:
        case "/Tx":
            return FormField(name=name, kind="text")
        case "/Btn":
            return _build_checkbox(raw, name)
        case "/Ch":
            return _build_choice(raw, name)
        case _:
            return FormField(name=name, kind=f"unknown ({ft})")


def _build_checkbox(raw: dict, name: str) -> CheckboxField:
    states = raw.get("/_States_", [])
    if len(states) == 2:
        if "/Off" in states:
            on_val = states[0] if states[0] != "/Off" else states[1]
            return CheckboxField(name=name, kind="checkbox", on_value=on_val, off_value="/Off")
        print(
            f"WARNING: Non-standard checkbox states for '{name}'. "
            "On/off values may be swapped — check the output visually."
        )
        return CheckboxField(name=name, kind="checkbox", on_value=states[0], off_value=states[1])
    return CheckboxField(name=name, kind="checkbox")


def _build_choice(raw: dict, name: str) -> ChoiceField:
    options = []
    for state in raw.get("/_States_", []):
        if isinstance(state, list) and len(state) >= 2:
            options.append({"value": state[0], "text": state[1]})
        else:
            options.append({"value": state, "text": state})
    return ChoiceField(name=name, kind="choice", choices=options)


def _extract_checkbox_on_value(resolved: dict, cb: CheckboxField) -> None:
    if cb.on_value:
        return
    try:
        ap_keys = list(resolved["/AP"]["/N"].keys())
        on_keys = [k for k in ap_keys if k != "/Off"]
        if on_keys:
            cb.on_value = on_keys[0]
            cb.off_value = "/Off"
    except (KeyError, TypeError, AttributeError):
        pass


def _flip_rect(rect: list, page_height: float) -> list[float]:
    left, bottom, right, top = [float(v) for v in rect]
    return [left, page_height - top, right, page_height - bottom]


def _extract_from_widgets(reader: PdfReader) -> list[FormField]:
    fields: list[FormField] = []
    for page_idx, page in enumerate(reader.pages):
        annots = page.get("/Annots")
        if not annots:
            continue
        ph = float(page.mediabox.height)
        for ann in annots:
            resolved = ann.get_object() if hasattr(ann, "get_object") else ann
            if resolved.get("/Subtype") != "/Widget" or not resolved.get("/FT"):
                continue
            name = resolved.get("/T")
            if not name:
                continue
            f = _build_field_from_dict(resolved, name)
            f.page = page_idx + 1
            raw_rect = resolved.get("/Rect")
            f.rect = _flip_rect(raw_rect, ph) if raw_rect else None
            if isinstance(f, CheckboxField):
                _extract_checkbox_on_value(resolved, f)
            fields.append(f)
    return fields


def _extract_from_acroform(reader: PdfReader) -> list[FormField]:
    raw_fields = reader.get_fields()
    if not raw_fields:
        return _extract_from_widgets(reader)

    by_name: dict[str, FormField] = {}
    radio_candidates: set[str] = set()

    for name, raw in raw_fields.items():
        if raw.get("/Kids"):
            if raw.get("/FT") == "/Btn":
                radio_candidates.add(name)
            continue
        by_name[name] = _build_field_from_dict(raw, name)

    radio_groups: dict[str, RadioGroup] = {}

    for page_idx, page in enumerate(reader.pages):
        ph = float(page.mediabox.height)
        for ann in page.get("/Annots", []):
            name = _full_field_name(ann)
            if name in by_name:
                by_name[name].page = page_idx + 1
                raw_rect = ann.get("/Rect")
                by_name[name].rect = _flip_rect(raw_rect, ph) if raw_rect else None
            elif name in radio_candidates:
                _collect_radio_option(ann, name, page_idx, ph, radio_groups)

    located = [f for f in by_name.values() if f.page > 0]
    for f in by_name.values():
        if f.page == 0:
            print(f"WARNING: Field '{f.name}' not found on any page, skipping")

    combined = located + list(radio_groups.values())
    combined.sort(key=_field_sort_key)
    return combined


def _collect_radio_option(
    ann: dict, name: str, page_idx: int, page_height: float, radio_groups: dict[str, RadioGroup]
) -> None:
    try:
        on_keys = [k for k in ann["/AP"]["/N"] if k != "/Off"]
    except KeyError:
        return
    if len(on_keys) != 1:
        return
    if name not in radio_groups:
        radio_groups[name] = RadioGroup(name=name, kind="radio_group", page=page_idx + 1, options=[])
    raw_rect = ann.get("/Rect")
    flipped = _flip_rect(raw_rect, page_height) if raw_rect else None
    radio_groups[name].options.append({"value": on_keys[0], "rect": flipped})


ROW_QUANTIZE = 10.0


def _field_sort_key(f: FormField) -> tuple:
    match f:
        case RadioGroup(options=opts) if opts:
            rect = opts[0].get("rect") or [0, 0, 0, 0]
        case _:
            rect = f.rect or [0, 0, 0, 0]
    row = int(rect[1] / ROW_QUANTIZE)
    return (f.page, row, rect[0])


def _field_to_dict(f: FormField) -> dict:
    result: dict = {"name": f.name, "kind": f.kind}
    if f.page:
        result["page"] = f.page
    if f.rect:
        result["rect"] = f.rect
    match f:
        case CheckboxField(on_value=on, off_value=off):
            if on:
                result["on_value"] = on
            if off:
                result["off_value"] = off
        case RadioGroup(options=opts):
            result["options"] = opts
        case ChoiceField(choices=opts):
            result["choices"] = opts
    return result


def _validate_fill_value(f: FormField, value: str) -> str | None:
    match f:
        case CheckboxField(on_value=on, off_value=off):
            if value not in (on, off):
                return f'ERROR: Invalid value "{value}" for checkbox "{f.name}". Use "{on}" (on) or "{off}" (off).'
        case RadioGroup(options=opts):
            valid = [opt["value"] for opt in opts]
            if value not in valid:
                return f'ERROR: Invalid value "{value}" for radio group "{f.name}". Valid: {valid}'
        case ChoiceField(choices=opts):
            valid = [opt["value"] for opt in opts]
            if value not in valid:
                return f'ERROR: Invalid value "{value}" for choice "{f.name}". Valid: {valid}'
    return None


def cmd_detect(args: list[str]) -> None:
    if len(args) != 1:
        print("Usage: formfill.py detect <file.pdf>")
        sys.exit(1)
    reader = PdfReader(str(Path(args[0])))
    if reader.get_fields() or _has_orphaned_widgets(reader):
        print("Fillable form fields detected")
    else:
        print("No fillable fields found — use layout.py to place text annotations manually")


def cmd_extract(args: list[str]) -> None:
    if len(args) != 2:
        print("Usage: formfill.py extract <input.pdf> <output.json>")
        sys.exit(1)
    pdf_path, json_path = args
    reader = PdfReader(pdf_path)
    fields = _extract_from_acroform(reader)
    output = [_field_to_dict(f) for f in fields]
    Path(json_path).parent.mkdir(parents=True, exist_ok=True)
    Path(json_path).write_text(json.dumps(output, indent=2))
    print(f"Wrote {len(output)} fields to {json_path}")


def cmd_fill(args: list[str]) -> None:
    if len(args) != 3:
        print("Usage: formfill.py fill <input.pdf> <values.json> <output.pdf>")
        sys.exit(1)
    input_path, values_path, output_path = args

    values = json.loads(Path(values_path).read_text())
    reader = PdfReader(input_path)
    fields = _extract_from_acroform(reader)
    meta_by_name = {f.name: f for f in fields}

    has_error = _validate_fill_entries(values, meta_by_name)
    if has_error:
        sys.exit(1)

    pages: dict[int, dict[str, str]] = {}
    for entry in values:
        if "value" in entry:
            pages.setdefault(entry["page"], {})[entry["name"]] = entry["value"]

    writer = PdfWriter(clone_from=reader)
    for pg, vals in pages.items():
        writer.update_page_form_field_values(writer.pages[pg - 1], vals, auto_regenerate=True)

    Path(output_path).parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "wb") as f:
        writer.write(f)

    print(f"Filled {sum(len(v) for v in pages.values())} fields → {output_path}")


def _validate_fill_entries(values: list[dict], meta_by_name: dict[str, FormField]) -> bool:
    has_error = False
    for entry in values:
        name = entry["name"]
        existing = meta_by_name.get(name)
        if not existing:
            print(f"ERROR: '{name}' is not a valid field name")
            has_error = True
        elif entry.get("page") and entry["page"] != existing.page:
            print(f"ERROR: Wrong page for '{name}' (got {entry['page']}, expected {existing.page})")
            has_error = True
        elif "value" in entry:
            err = _validate_fill_value(existing, entry["value"])
            if err:
                print(err)
                has_error = True
    return has_error


SUBCOMMANDS = {
    "detect": cmd_detect,
    "extract": cmd_extract,
    "fill": cmd_fill,
}


def main() -> None:
    if len(sys.argv) < 2 or sys.argv[1] not in SUBCOMMANDS:
        print(f"Usage: formfill.py <{'|'.join(SUBCOMMANDS)}> [args...]")
        sys.exit(1)
    SUBCOMMANDS[sys.argv[1]](sys.argv[2:])


if __name__ == "__main__":
    main()

#!/usr/bin/env bun
/**
 * Presentation CLI — create, manage, validate, preview and export HTML slide decks.
 *
 * Usage: bun run presentation.ts <action> [args as JSON]
 *
 * Actions:
 *   create_slide        '{"presentation_name":"my-deck","slide_number":1,"slide_title":"Intro","content":"<div>...</div>","presentation_title":"My Deck"}'
 *   list_slides         '{"presentation_name":"my-deck"}'
 *   delete_slide        '{"presentation_name":"my-deck","slide_number":1}'
 *   list_presentations
 *   delete_presentation '{"presentation_name":"my-deck"}'
 *   validate_slide      '{"presentation_name":"my-deck","slide_number":1}'
 *   export_pdf          '{"presentation_name":"my-deck"}'
 *   export_pptx         '{"presentation_name":"my-deck"}'
 *   preview             '{"presentation_name":"my-deck"}'
 */

import { writeFileSync, readFileSync, mkdirSync, existsSync, readdirSync, rmSync, unlinkSync, statSync } from "fs";
import { resolve, join, dirname, extname } from "path";
import { execSync } from "child_process";

const PRESENTATIONS_DIR = "presentations";
const SKILL_DIR = dirname(new URL(import.meta.url).pathname);
const SCRIPTS_DIR = join(SKILL_DIR, "scripts");

// ── Types ──────────────────────────────────────────────────────────────────

interface SlideMetadata { title: string; filename: string; file_path: string; created_at: string; }
interface PresentationMetadata {
  presentation_name: string; title: string; description: string;
  slides: Record<string, SlideMetadata>; created_at: string; updated_at: string;
}

// ── Helpers ────────────────────────────────────────────────────────────────

function sanitizeFilename(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9_-]/g, "").slice(0, 80);
}

function ensurePresentationsDir(base: string): string {
  const dir = resolve(base, PRESENTATIONS_DIR);
  try {
    mkdirSync(dir, { recursive: true });
  } catch (err: unknown) {
    const code = (err as { code?: string }).code;
    if (code === "EACCES" || code === "EROFS") {
      const fallback = resolve(process.cwd(), PRESENTATIONS_DIR);
      mkdirSync(fallback, { recursive: true });
      return fallback;
    }
    throw err;
  }
  return dir;
}

function ensurePresentationDir(base: string, name: string): { safeName: string; path: string; presDir: string } {
  const safeName = sanitizeFilename(name);
  const presDir = ensurePresentationsDir(base);
  const path = join(presDir, safeName);
  mkdirSync(path, { recursive: true });
  return { safeName, path, presDir };
}

function loadMetadata(presentationPath: string): PresentationMetadata {
  const metaPath = join(presentationPath, "metadata.json");
  if (existsSync(metaPath)) return JSON.parse(readFileSync(metaPath, "utf-8"));
  return { presentation_name: "", title: "Presentation", description: "", slides: {}, created_at: new Date().toISOString(), updated_at: new Date().toISOString() };
}

function saveMetadata(presentationPath: string, metadata: PresentationMetadata): void {
  metadata.updated_at = new Date().toISOString();
  writeFileSync(join(presentationPath, "metadata.json"), JSON.stringify(metadata, null, 2));
}

function createSlideHtml(content: string, slideNumber: number, presentationTitle: string): string {
  return `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=1920, initial-scale=1.0">
    <title>${presentationTitle} - Slide ${slideNumber}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet">
    <script src="https://d3js.org/d3.v7.min.js" async></script>
    <script src="https://cdn.jsdelivr.net/npm/chart.js@3.9.1" async></script>
    <style>
        * { font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; }
        body { height: 1080px; width: 1920px; margin: 0; padding: 0; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`;
}

function generateViewer(presPath: string, metadata: PresentationMetadata): void {
  const viewerTemplatePath = join(SKILL_DIR, "viewer.html");
  if (!existsSync(viewerTemplatePath)) return;
  const slides = Object.entries(metadata.slides)
    .map(([num, data]) => ({ number: parseInt(num), title: data.title || `Slide ${num}`, filename: data.filename }))
    .sort((a, b) => a.number - b.number);
  const presData = JSON.stringify({ title: metadata.title || metadata.presentation_name || "Presentation", slides });
  const template = readFileSync(viewerTemplatePath, "utf-8");
  writeFileSync(join(presPath, "viewer.html"), template.replace("{{TITLE}}", metadata.title || "Presentation").replace("{{PRESENTATION_DATA}}", presData));
}

function runPythonScript(script: string, args: string[], timeoutMs = 300_000): string {
  const isLinux = process.platform === "linux";
  const shellArg = (value: string) => `'${value.replace(/'/g, `'\\''`)}'`;
  const scriptArgs = [script, ...args].map(shellArg).join(" ");
  const cmd = isLinux
    ? `python3 ${scriptArgs}`
    : `uv run --managed-python --python 3.12 ${scriptArgs}`;
  const env: Record<string, string | undefined> = { ...process.env };
  if (!isLinux) {
    env.UV_CACHE_DIR = env.UV_CACHE_DIR ?? join(process.env.HOME ?? "/tmp", ".cache", "uv");
    env.PYENV_VERSION = "system";
  }
  try {
    return execSync(cmd, { cwd: SCRIPTS_DIR, timeout: timeoutMs, encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], env }).trim();
  } catch (e: unknown) {
    const err = e as { stdout?: string; stderr?: string; message?: string };
    const stdout = err.stdout?.trim() ?? "";
    if (stdout) { try { const p = JSON.parse(stdout); if (p.success === false) return stdout; } catch {} }
    return JSON.stringify({ success: false, error: err.stderr?.trim() || err.message || "Python script failed" });
  }
}

function out(data: unknown): void { console.log(JSON.stringify(data, null, 2)); }

// ── Actions ────────────────────────────────────────────────────────────────

function doCreateSlide(base: string, presentation_name: string, slide_number: number, slide_title: string, content: string, presentation_title: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  if (!slide_number || slide_number < 1) return out({ success: false, error: "slide_number must be >= 1" });
  if (!slide_title) return out({ success: false, error: "slide_title is required" });
  if (!content) return out({ success: false, error: "content is required" });

  const { safeName, path: presPath, presDir } = ensurePresentationDir(base, presentation_name);
  mkdirSync(join(presDir, "images"), { recursive: true });

  const metadata = loadMetadata(presPath);
  metadata.presentation_name = presentation_name;
  if (presentation_title !== "Presentation") metadata.title = presentation_title;

  const html = createSlideHtml(content, slide_number, presentation_title);
  const filename = `slide_${String(slide_number).padStart(2, "0")}.html`;
  writeFileSync(join(presPath, filename), html);

  const relPath = `${PRESENTATIONS_DIR}/${safeName}/${filename}`;
  metadata.slides[String(slide_number)] = { title: slide_title, filename, file_path: relPath, created_at: new Date().toISOString() };
  saveMetadata(presPath, metadata);
  generateViewer(presPath, metadata);

  out({ success: true, action: "create_slide", presentation_name, presentation_path: `${PRESENTATIONS_DIR}/${safeName}`, slide_number, slide_title, slide_file: relPath, total_slides: Object.keys(metadata.slides).length });
}

function doListSlides(base: string, presentation_name: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: true, presentation_name, slides: [], total_slides: 0 });
  const metadata = loadMetadata(presPath);
  const slides = Object.entries(metadata.slides).map(([num, data]) => ({ slide_number: parseInt(num), ...data })).sort((a, b) => a.slide_number - b.slide_number);
  out({ success: true, presentation_name, presentation_title: metadata.title, slides, total_slides: slides.length, presentation_path: `${PRESENTATIONS_DIR}/${safeName}` });
}

function doDeleteSlide(base: string, presentation_name: string, slide_number: number) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  if (!slide_number || slide_number < 1) return out({ success: false, error: "slide_number must be >= 1" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: false, error: `Presentation '${presentation_name}' not found` });
  const metadata = loadMetadata(presPath);
  const key = String(slide_number);
  if (!metadata.slides[key]) return out({ success: false, error: `Slide ${slide_number} not found` });
  const slideInfo = metadata.slides[key];
  try { unlinkSync(join(presPath, slideInfo.filename)); } catch {}
  delete metadata.slides[key];
  saveMetadata(presPath, metadata);
  generateViewer(presPath, metadata);
  out({ success: true, action: "delete_slide", presentation_name, deleted_slide: slide_number, deleted_title: slideInfo.title, remaining_slides: Object.keys(metadata.slides).length });
}

function doListPresentations(base: string) {
  const presDir = resolve(base, PRESENTATIONS_DIR);
  if (!existsSync(presDir)) return out({ success: true, presentations: [], total_count: 0 });
  const presentations = readdirSync(presDir, { withFileTypes: true })
    .filter(d => d.isDirectory() && !d.name.startsWith(".") && d.name !== "images")
    .map(d => { const meta = loadMetadata(join(presDir, d.name)); return { folder: d.name, title: meta.title || d.name, description: meta.description || "", total_slides: Object.keys(meta.slides).length, created_at: meta.created_at, updated_at: meta.updated_at }; });
  out({ success: true, presentations, total_count: presentations.length });
}

function doDeletePresentation(base: string, presentation_name: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: false, error: `Presentation '${presentation_name}' not found` });
  rmSync(presPath, { recursive: true, force: true });
  out({ success: true, action: "delete_presentation", presentation_name, deleted_path: `${PRESENTATIONS_DIR}/${safeName}` });
}

function doValidateSlide(base: string, presentation_name: string, slide_number: number) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  if (!slide_number || slide_number < 1) return out({ success: false, error: "slide_number must be >= 1" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  const metadata = loadMetadata(presPath);
  const key = String(slide_number);
  if (!metadata.slides[key]) return out({ success: false, error: `Slide ${slide_number} not found` });
  const slidePath = join(resolve(base), metadata.slides[key].file_path);
  if (!existsSync(slidePath)) return out({ success: false, error: `Slide file not found: ${slidePath}` });
  const raw = runPythonScript("validate_slide.py", [slidePath]);
  try { out({ ...JSON.parse(raw), action: "validate_slide", presentation_name, slide_number }); } catch { out({ success: false, error: raw }); }
}

function exportPresentationFile(presPath: string, safeName: string, format: "pdf" | "pptx"): { success: boolean; path?: string; filename?: string; result?: Record<string, unknown>; error?: string } {
  const filename = `${safeName}.${format}`;
  const outPath = join(presPath, filename);
  const script = format === "pdf" ? "convert_pdf.py" : "convert_pptx.py";
  const raw = runPythonScript(script, [presPath, outPath]);
  try {
    const result = JSON.parse(raw) as Record<string, unknown>;
    if (result.success === true) return { success: true, path: outPath, filename, result };
    return { success: false, result, error: String(result.error || raw) };
  } catch {
    return { success: false, error: raw };
  }
}

function doExportPdf(base: string, presentation_name: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: false, error: `Presentation '${presentation_name}' not found` });
  const exported = exportPresentationFile(presPath, safeName, "pdf");
  out(exported.success
    ? { ...exported.result, action: "export_pdf", presentation_name, relative_path: `${PRESENTATIONS_DIR}/${safeName}/${safeName}.pdf` }
    : { ...(exported.result || {}), success: false, error: exported.error || "PDF export failed" });
}

function doExportPptx(base: string, presentation_name: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: false, error: `Presentation '${presentation_name}' not found` });
  const exported = exportPresentationFile(presPath, safeName, "pptx");
  out(exported.success
    ? { ...exported.result, action: "export_pptx", presentation_name, relative_path: `${PRESENTATIONS_DIR}/${safeName}/${safeName}.pptx` }
    : { ...(exported.result || {}), success: false, error: exported.error || "PPTX export failed" });
}

function doPreview(base: string, presentation_name: string) {
  if (!presentation_name) return out({ success: false, error: "presentation_name is required" });
  const safeName = sanitizeFilename(presentation_name);
  const presPath = join(resolve(base, PRESENTATIONS_DIR), safeName);
  if (!existsSync(presPath)) return out({ success: false, error: `Presentation '${presentation_name}' not found` });
  generateViewer(presPath, loadMetadata(presPath));
  out({
    success: true, action: "preview", presentation_name,
    viewer_file: `${PRESENTATIONS_DIR}/${safeName}/viewer.html`,
    message: `Viewer generated at ${PRESENTATIONS_DIR}/${safeName}/viewer.html. To serve it, run: bun run "$SCRIPT" serve '{"presentation_name":"${safeName}"}'`,
  });
}

// ── Serve (on-demand viewer server) ───────────────────────────────────────

const SERVE_MIME_TYPES: Record<string, string> = {
  ".html": "text/html; charset=utf-8",
  ".css": "text/css; charset=utf-8",
  ".js": "application/javascript; charset=utf-8",
  ".json": "application/json; charset=utf-8",
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".gif": "image/gif",
  ".svg": "image/svg+xml",
  ".webp": "image/webp",
  ".ico": "image/x-icon",
  ".woff": "font/woff",
  ".woff2": "font/woff2",
  ".ttf": "font/ttf",
  ".pdf": "application/pdf",
  ".pptx": "application/vnd.openxmlformats-officedocument.presentationml.presentation",
};

function serveMime(filePath: string): string {
  return SERVE_MIME_TYPES[extname(filePath).toLowerCase()] || "application/octet-stream";
}

function serveFile(filePath: string, downloadName?: string): Response {
  if (!existsSync(filePath) || !statSync(filePath).isFile()) {
    return new Response("Not found: " + filePath, { status: 404 });
  }
  const data = readFileSync(filePath);
  const headers: Record<string, string> = { "Content-Type": serveMime(filePath), "Cache-Control": "no-cache" };
  if (downloadName) headers["Content-Disposition"] = `attachment; filename="${downloadName.replace(/"/g, "")}"`;
  return new Response(data, {
    headers,
  });
}

function buildViewerHtml(presDir: string, metadata: PresentationMetadata): string {
  const viewerTemplatePath = join(SKILL_DIR, "viewer.html");
  if (!existsSync(viewerTemplatePath)) {
    return "<html><body><p>viewer.html template not found</p></body></html>";
  }
  const slides = Object.entries(metadata.slides)
    .map(([num, data]) => ({ number: parseInt(num), title: data.title || `Slide ${num}`, filename: data.filename || `slide_${String(num).padStart(2, "0")}.html` }))
    .sort((a, b) => a.number - b.number);
  const presData = JSON.stringify({ title: metadata.title || metadata.presentation_name || "Presentation", slides });
  const template = readFileSync(viewerTemplatePath, "utf-8");
  return template.replace("{{TITLE}}", metadata.title || "Presentation").replace("{{PRESENTATION_DATA}}", presData);
}

function listAllPresentations(presRoot: string): Array<{ name: string; title: string; total_slides: number }> {
  if (!existsSync(presRoot)) return [];
  return readdirSync(presRoot, { withFileTypes: true })
    .filter(d => d.isDirectory() && !d.name.startsWith(".") && d.name !== "images")
    .map(d => {
      const meta = loadMetadata(join(presRoot, d.name));
      return { name: d.name, title: meta.title || d.name, total_slides: Object.keys(meta.slides || {}).length };
    });
}

function buildIndexHtml(pres: Array<{ name: string; title: string; total_slides: number }>): string {
  const items = pres.map(p =>
    `<li><a href="/presentations/${p.name}/"><span>${p.title}</span><span class="count">${p.total_slides} slides</span></a></li>`
  ).join("");
  const empty = pres.length === 0 ? '<p class="empty">No presentations yet. Create one with the presentation CLI.</p>' : "";
  return `<!DOCTYPE html><html><head><title>Presentations</title>
<style>body{font-family:sans-serif;padding:2rem;max-width:800px;margin:0 auto}
h1{font-size:1.5rem;margin-bottom:1.5rem}ul{list-style:none;padding:0}li{margin:0.5rem 0}
a{display:flex;align-items:center;gap:0.5rem;padding:0.75rem 1rem;border:1px solid #e5e7eb;border-radius:0.5rem;text-decoration:none;color:inherit}
a:hover{background:#f9fafb}.count{font-size:0.75rem;color:#6b7280;margin-left:auto}.empty{color:#6b7280}
</style></head><body><h1>Presentations (${pres.length})</h1><ul>${items}</ul>${empty}</body></html>`;
}

function doServe(base: string, port: number) {
  const presRoot = resolve(base, PRESENTATIONS_DIR);
  const corsHeaders = { "Access-Control-Allow-Origin": "*", "Cache-Control": "no-cache" };

  const server = Bun.serve({
    port,
    hostname: "0.0.0.0",
    fetch(req) {
      const url = new URL(req.url);
      const pathname = decodeURIComponent(url.pathname);

      // Index
      if (pathname === "/" || pathname === "/index.html") {
        const pres = listAllPresentations(presRoot);
        return new Response(buildIndexHtml(pres), { headers: { "Content-Type": "text/html; charset=utf-8", ...corsHeaders } });
      }

      // /presentations/<name>[/...]
      const presMatch = pathname.match(/^\/presentations\/([^/]+)\/?(.*)$/);
      if (presMatch) {
        const presName = presMatch[1];
        if (!presName) {
          return new Response("Presentation not found", { status: 404, headers: corsHeaders });
        }
        const rest = presMatch[2] || "";
        const presDir = join(presRoot, presName);

        if (!existsSync(presDir)) {
          return new Response("Presentation not found: " + presName, { status: 404, headers: corsHeaders });
        }

        const metadata = loadMetadata(presDir);

        // Viewer
        if (rest === "" || rest === "viewer" || rest === "viewer.html" || rest === "index.html") {
          const html = buildViewerHtml(presDir, metadata);
          return new Response(html, { headers: { "Content-Type": "text/html; charset=utf-8", ...corsHeaders } });
        }

        if (rest === "download/pdf" || rest === "download/pptx") {
          const format = rest.endsWith("pdf") ? "pdf" : "pptx";
          const exported = exportPresentationFile(presDir, presName, format);
          if (!exported.success || !exported.path || !exported.filename) {
            return new Response(exported.error || `Failed to export ${format.toUpperCase()}`, { status: 500, headers: corsHeaders });
          }
          return serveFile(exported.path, exported.filename);
        }

        // ../images/ references from within slide iframes
        if (rest.startsWith("../images/") || rest.startsWith("%2E%2E/images/")) {
          const imgName = rest.replace(/^(\.\.\/|%2E%2E\/)images\//, "");
          return serveFile(join(presRoot, "images", imgName));
        }

        // images/ relative to presentation dir
        if (rest.startsWith("images/")) {
          return serveFile(join(presRoot, "images", rest.slice("images/".length)));
        }

        // Any file inside the presentation dir
        return serveFile(join(presDir, rest));
      }

      // /images/<name> — shared images
      if (pathname.startsWith("/images/")) {
        return serveFile(join(presRoot, "images", pathname.slice("/images/".length)));
      }

      return new Response("Not found", { status: 404, headers: corsHeaders });
    },
  });

  const pres = listAllPresentations(presRoot);
  console.log(`\n  Presentation Viewer`);
  console.log(`  http://localhost:${server.port}\n`);
  console.log(`  Serving ${pres.length} presentation(s) from ${presRoot}`);
  pres.forEach(p => console.log(`  → http://localhost:${server.port}/presentations/${p.name}/  (${p.total_slides} slides)`));
  console.log(`\n  Press Ctrl+C to stop\n`);

  // Output JSON for programmatic consumption
  out({
    success: true,
    action: "serve",
    port: server.port,
    url: `http://localhost:${server.port}`,
    presentations: pres.map(p => ({ name: p.name, url: `http://localhost:${server.port}/presentations/${p.name}/`, total_slides: p.total_slides })),
    message: `Viewer running at http://localhost:${server.port}`,
  });
}

// ── Dispatch ───────────────────────────────────────────────────────────────

const [action, rawArgs] = process.argv.slice(2);
const args = rawArgs ? JSON.parse(rawArgs) : {};
const base = args.output_dir ?? process.cwd();

switch (action) {
  case "create_slide":        doCreateSlide(base, args.presentation_name ?? "", args.slide_number ?? 0, args.slide_title ?? "", args.content ?? "", args.presentation_title ?? "Presentation"); break;
  case "list_slides":         doListSlides(base, args.presentation_name ?? ""); break;
  case "delete_slide":        doDeleteSlide(base, args.presentation_name ?? "", args.slide_number ?? 0); break;
  case "list_presentations":  doListPresentations(base); break;
  case "delete_presentation": doDeletePresentation(base, args.presentation_name ?? ""); break;
  case "validate_slide":      doValidateSlide(base, args.presentation_name ?? "", args.slide_number ?? 0); break;
  case "export_pdf":          doExportPdf(base, args.presentation_name ?? ""); break;
  case "export_pptx":         doExportPptx(base, args.presentation_name ?? ""); break;
  case "preview":             doPreview(base, args.presentation_name ?? ""); break;
  case "serve":               doServe(base, parseInt(args.port ?? process.env.PORT ?? "3210")); break;
  default:
    console.error(`Unknown action: ${action}. Use: create_slide | list_slides | delete_slide | list_presentations | delete_presentation | validate_slide | export_pdf | export_pptx | preview | serve`);
    process.exit(1);
}

"""Convert HTML presentation slides to a single PDF.

Usage: uv run convert_pdf.py <presentation_dir> <output_path>

Reads metadata.json from <presentation_dir>, renders each slide HTML
at 1920x1080 via Playwright Chromium, merges into a single PDF.
"""

import asyncio
import json
import os
import sys
import tempfile
from pathlib import Path

from playwright.async_api import async_playwright
from pypdf import PdfWriter, PdfReader


def find_chromium() -> str | None:
    """Auto-detect Chromium executable path for the current platform."""
    env_path = os.environ.get("PLAYWRIGHT_CHROMIUM_EXECUTABLE_PATH")
    if env_path and os.path.isfile(env_path):
        return env_path
    for p in (
        "/usr/bin/chromium-browser",
        "/usr/bin/chromium",
        "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        "/Applications/Chromium.app/Contents/MacOS/Chromium",
        "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
    ):
        if os.path.isfile(p):
            return p
    return None


async def render_slide_to_pdf(
    browser, slide_info: dict, temp_dir: Path, max_retries: int = 3
) -> Path:
    """Render a single HTML slide to PDF with retry logic."""
    html_path = slide_info["path"]
    slide_num = slide_info["number"]
    last_error = None

    for attempt in range(max_retries):
        page = None
        try:
            if attempt > 0:
                await asyncio.sleep(2.0 * attempt)

            page = await browser.new_page()
            await page.set_viewport_size({"width": 1920, "height": 1080})
            await page.emulate_media(media="screen")
            await page.evaluate(
                "() => { Object.defineProperty(window, 'devicePixelRatio', { get: () => 1 }); }"
            )

            file_url = f"file://{html_path.resolve()}"
            await page.goto(file_url, wait_until="networkidle", timeout=30000)
            await page.wait_for_timeout(3000)

            await page.evaluate("""
                () => {
                    const sc = document.querySelector('.slide-container');
                    if (sc) { sc.style.width='1920px'; sc.style.height='1080px'; sc.style.transform='none'; sc.style.maxWidth='none'; sc.style.maxHeight='none'; }
                    document.body.style.margin='0'; document.body.style.padding='0';
                    document.body.style.width='1920px'; document.body.style.height='1080px';
                    document.body.style.overflow='hidden';
                }
            """)
            await page.wait_for_timeout(1000)

            temp_pdf = temp_dir / f"slide_{slide_num:02d}.pdf"
            await page.pdf(
                path=str(temp_pdf),
                width="1920px",
                height="1080px",
                margin={"top": "0", "right": "0", "bottom": "0", "left": "0"},
                print_background=True,
                prefer_css_page_size=False,
            )
            return temp_pdf

        except Exception as e:
            last_error = e
            err = str(e).lower()
            retryable = any(
                kw in err
                for kw in [
                    "target closed", "crashed", "protocol error",
                    "printtopdf", "session closed", "timeout",
                ]
            )
            if retryable and attempt < max_retries - 1:
                continue
            break
        finally:
            if page:
                try:
                    await page.close()
                except Exception:
                    pass

    raise RuntimeError(
        f"Slide {slide_num} failed after {max_retries} attempts: {last_error}"
    )


def combine_pdfs(pdf_paths: list[Path], output_path: Path) -> None:
    """Merge multiple single-page PDFs into one."""
    writer = PdfWriter()
    for p in pdf_paths:
        if p.exists():
            reader = PdfReader(str(p))
            for pg in reader.pages:
                writer.add_page(pg)
    with open(output_path, "wb") as f:
        writer.write(f)


async def convert(presentation_dir: str, output_path: str) -> dict:
    """Main conversion entrypoint."""
    pres_dir = Path(presentation_dir).resolve()
    meta_path = pres_dir / "metadata.json"

    if not pres_dir.exists():
        return {"success": False, "error": f"Directory not found: {pres_dir}"}
    if not meta_path.exists():
        return {"success": False, "error": f"metadata.json not found in {pres_dir}"}

    with open(meta_path, "r") as f:
        metadata = json.load(f)

    slides_info = []
    for num_str, data in metadata.get("slides", {}).items():
        file_path = data.get("file_path", "")
        html_path = (pres_dir.parent.parent / file_path) if file_path else None
        if html_path and html_path.exists():
            slides_info.append({
                "number": int(num_str),
                "title": data.get("title", f"Slide {num_str}"),
                "path": html_path,
            })

    if not slides_info:
        return {"success": False, "error": "No valid slides found"}

    slides_info.sort(key=lambda s: s["number"])

    launch_opts: dict = {
        "headless": True,
        "args": [
            "--no-sandbox",
            "--disable-setuid-sandbox",
            "--disable-dev-shm-usage",
            "--disable-gpu",
            "--force-device-scale-factor=1",
        ],
    }
    chromium = find_chromium()
    if chromium:
        launch_opts["executable_path"] = chromium

    with tempfile.TemporaryDirectory() as tmp:
        tmp_path = Path(tmp)

        async with async_playwright() as p:
            browser = await p.chromium.launch(**launch_opts)

            try:
                sem = asyncio.Semaphore(5)

                async def render_limited(si):
                    async with sem:
                        return await render_slide_to_pdf(browser, si, tmp_path)

                pdf_paths = await asyncio.gather(
                    *[render_limited(si) for si in slides_info]
                )
            finally:
                await browser.close()

        sorted_paths = sorted(pdf_paths, key=lambda p: int(p.stem.split("_")[1]))
        out = Path(output_path)
        out.parent.mkdir(parents=True, exist_ok=True)
        combine_pdfs(sorted_paths, out)

    return {
        "success": True,
        "output_path": str(out),
        "total_slides": len(slides_info),
    }


def main():
    if len(sys.argv) != 3:
        print(json.dumps({"success": False, "error": "Usage: convert_pdf.py <presentation_dir> <output_path>"}))
        sys.exit(1)

    result = asyncio.run(convert(sys.argv[1], sys.argv[2]))
    print(json.dumps(result))
    sys.exit(0 if result["success"] else 1)


if __name__ == "__main__":
    main()

"""Convert HTML presentation slides to PPTX with editable text.

Usage: uv run convert_pptx.py <presentation_dir> <output_path>

Three-layer PPTX per slide (matching Suna's approach):
  1. Clean background screenshot (text + visual elements hidden)
  2. Individual visual element screenshots (positioned exactly)
  3. Native editable text boxes (extracted via DOM inspection)
"""

import asyncio
import json
import os
import re
import sys
import tempfile
from dataclasses import dataclass, field
from pathlib import Path

from playwright.async_api import async_playwright
from pptx import Presentation
from pptx.util import Inches, Pt
from pptx.enum.text import PP_ALIGN
from pptx.dml.color import RGBColor


def find_chromium() -> str | None:
    """Auto-detect Chromium executable path for the current platform."""
    env_path = os.environ.get("PLAYWRIGHT_CHROMIUM_EXECUTABLE_PATH")
    if env_path and os.path.isfile(env_path):
        return env_path
    for p in (
        "/usr/bin/chromium-browser",
        "/usr/bin/chromium",
        "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        "/Applications/Chromium.app/Contents/MacOS/Chromium",
        "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
    ):
        if os.path.isfile(p):
            return p
    return None


@dataclass
class TextElement:
    """Extracted text element with position and styling."""
    text: str
    x: float
    y: float
    width: float
    height: float
    font_family: str
    font_size: float
    font_weight: str
    color: str
    text_align: str
    line_height: float
    tag: str
    depth: int = 0
    style: dict = field(default_factory=dict)


def parse_color(color_str: str) -> tuple[int, int, int]:
    """Parse CSS color string to RGB tuple."""
    if not color_str:
        return (0, 0, 0)
    color_str = color_str.strip().lower()

    if color_str.startswith("#"):
        h = color_str[1:]
        if len(h) == 3:
            h = "".join(c * 2 for c in h)
        try:
            return (int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16))
        except ValueError:
            return (0, 0, 0)

    m = re.match(r"rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)", color_str)
    if m:
        return (int(m.group(1)), int(m.group(2)), int(m.group(3)))

    named = {
        "black": (0, 0, 0), "white": (255, 255, 255), "red": (255, 0, 0),
        "green": (0, 128, 0), "blue": (0, 0, 255), "yellow": (255, 255, 0),
        "gray": (128, 128, 128), "grey": (128, 128, 128),
        "orange": (255, 165, 0), "purple": (128, 0, 128),
    }
    return named.get(color_str, (0, 0, 0))


def is_bold(weight_str: str) -> bool:
    """Parse CSS font-weight to bold boolean."""
    if not weight_str:
        return False
    w = weight_str.strip().lower()
    return w in ("bold", "bolder", "700", "800", "900") or (
        w.isdigit() and int(w) >= 700
    )


# ── JS snippets injected into Playwright ──

JS_EXTRACT_VISUAL_ELEMENTS = r"""
() => {
    function hasVisual(el, cs) {
        if (['IMG','SVG','CANVAS','VIDEO','IFRAME'].includes(el.tagName)) return true;
        if (cs.backgroundImage && cs.backgroundImage !== 'none') return true;
        const bg = cs.backgroundColor;
        if (bg && bg !== 'rgba(0, 0, 0, 0)' && bg !== 'transparent') return true;
        if (cs.borderStyle && cs.borderStyle !== 'none' && cs.borderWidth !== '0px') return true;
        if (cs.boxShadow && cs.boxShadow !== 'none') return true;
        return false;
    }
    function skip(el, cs) {
        const textOnly = ['H1','H2','H3','H4','H5','H6','P','A','SPAN','STRONG','EM','U','BUTTON','LABEL','SMALL','CODE'];
        if (textOnly.includes(el.tagName)) return true;
        if (cs.display === 'none' || cs.visibility === 'hidden') return true;
        return false;
    }
    function walk(el, depth) {
        if (!el || el.nodeType !== 1) return [];
        const cs = getComputedStyle(el);
        const r = el.getBoundingClientRect();
        if (r.width === 0 || r.height === 0) return [];
        if (skip(el, cs)) return [];
        const out = [];
        if (hasVisual(el, cs) && r.width <= 1700) {
            const cid = 'vc-' + Date.now() + '-' + Math.random().toString(36).substr(2,6);
            el.setAttribute('data-capture-id', cid);
            out.push({type:'visual', captureId:cid, x:r.left, y:r.top, width:r.width, height:r.height, tag:el.tagName.toLowerCase(), depth});
        }
        for (const ch of el.children) out.push(...walk(ch, depth+1));
        return out;
    }
    // make text transparent first
    function hideText(el) {
        if (el.nodeType !== 1) return;
        if (el.textContent && el.textContent.trim()) {
            el.style.color = 'transparent';
            el.style.textShadow = 'none';
            el.style.webkitTextFillColor = 'transparent';
        }
        for (const ch of el.children) hideText(ch);
    }
    hideText(document.body);
    const elems = walk(document.body, 0);
    elems.sort((a,b) => a.depth !== b.depth ? a.depth - b.depth : a.y - b.y);
    return elems;
}
"""

JS_EXTRACT_TEXT = r"""
() => {
    function extract(el) {
        if (!el || el.nodeType !== 1) return [];
        const cs = getComputedStyle(el);
        const r = el.getBoundingClientRect();
        if (cs.display === 'none' || cs.visibility === 'hidden') return [];
        if (r.width === 0 || r.height === 0) return [];
        const out = [];
        let dt = '';
        for (const n of el.childNodes) { if (n.nodeType === 3) dt += n.textContent; }
        dt = dt.trim();
        if (dt) {
            const fsm = cs.fontSize.match(/([0-9.]+)px/);
            const fps = fsm ? parseFloat(fsm[1]) : 16;
            out.push({
                text: dt, x: r.left, y: r.top, width: r.width, height: r.height,
                fps, tag: el.tagName.toLowerCase(),
                style: {
                    fontFamily: cs.fontFamily, fontWeight: cs.fontWeight, color: cs.color,
                    textAlign: cs.textAlign, lineHeight: cs.lineHeight,
                    letterSpacing: cs.letterSpacing, textTransform: cs.textTransform,
                    webkitBackgroundClip: cs.webkitBackgroundClip,
                    backgroundImage: cs.backgroundImage
                }
            });
        }
        for (const ch of el.children) out.push(...extract(ch));
        return out;
    }
    const all = extract(document.body);
    all.sort((a,b) => Math.abs(a.y-b.y) < 5 ? a.x-b.x : a.y-b.y);
    return all;
}
"""


async def extract_visual_elements(page, html_path: Path, temp_dir: Path) -> list[dict]:
    """Extract visual elements as positioned screenshots."""
    elements = []
    await page.set_viewport_size({"width": 1920, "height": 1080})
    await page.emulate_media(media="screen")
    await page.goto(f"file://{html_path.resolve()}", wait_until="networkidle", timeout=25000)
    await page.wait_for_timeout(1000)

    visual_data = await page.evaluate(JS_EXTRACT_VISUAL_ELEMENTS)

    for i, d in enumerate(visual_data or []):
        try:
            x = max(0, min(d["x"], 1920))
            y = max(0, min(d["y"], 1080))
            w = min(d["width"], 1920 - x)
            h = min(d["height"], 1080 - y)
            if w < 5 or h < 5:
                continue

            clone_js = """
            (data) => {
                const el = document.querySelector(`[data-capture-id="${data.captureId}"]`);
                if (!el) return {success:false};
                const clone = el.cloneNode(true);
                function cpStyles(orig, cl, root, psvg) {
                    const cs = getComputedStyle(orig);
                    let s = '';
                    for (const p of cs) s += p + ':' + cs.getPropertyValue(p) + ';';
                    cl.style.cssText = s;
                    if (!root && orig.tagName !== 'svg' && orig.tagName !== 'SVG' &&
                        orig.namespaceURI !== 'http://www.w3.org/2000/svg' && !psvg)
                        cl.style.opacity = '0';
                    const isSvg = orig.tagName === 'svg' || orig.tagName === 'SVG';
                    for (let j=0; j<orig.children.length && j<cl.children.length; j++)
                        cpStyles(orig.children[j], cl.children[j], false, isSvg||psvg);
                }
                cpStyles(el, clone, true, false);
                const ctr = document.createElement('div');
                ctr.id = 'cap-' + Date.now();
                ctr.style.cssText = `position:fixed;top:0;left:0;width:${data.width}px;height:${data.height}px;background:transparent;z-index:999999;padding:0;margin:0;border:none;overflow:hidden;`;
                clone.style.position = 'absolute';
                clone.style.top = '0';
                clone.style.left = '0';
                clone.style.margin = '0';
                clone.style.transform = 'none';
                ctr.appendChild(clone);
                document.body.appendChild(ctr);
                return {success:true, containerId:ctr.id, rect:{x:0,y:0,width:data.width,height:data.height}};
            }
            """
            result = await page.evaluate(clone_js, d)
            if not result.get("success"):
                continue

            await page.wait_for_timeout(100)
            cid = result["containerId"]

            await page.evaluate(f"""() => {{
                window._origHtml = document.documentElement.style.background || '';
                window._origBody = document.body.style.background || '';
                document.documentElement.style.background = 'transparent';
                document.body.style.background = 'transparent';
                document.body.style.visibility = 'hidden';
                const c = document.getElementById('{cid}');
                if (c) c.style.visibility = 'visible';
            }}""")

            img_path = temp_dir / f"ve_{html_path.stem}_{i:03d}.png"
            cr = result["rect"]
            await page.screenshot(
                path=str(img_path), full_page=False, omit_background=True,
                clip={"x": cr["x"], "y": cr["y"], "width": cr["width"], "height": cr["height"]},
            )

            await page.evaluate(f"""() => {{
                document.documentElement.style.background = window._origHtml || '';
                document.body.style.background = window._origBody || '';
                document.body.style.visibility = 'visible';
                const c = document.getElementById('{cid}');
                if (c) c.remove();
            }}""")

            elements.append({
                "x": d["x"], "y": d["y"], "width": d["width"], "height": d["height"],
                "tag": d["tag"], "image_path": img_path, "depth": d["depth"],
            })
        except Exception:
            try:
                await page.evaluate("""() => {
                    document.documentElement.style.background = window._origHtml || '';
                    document.body.style.background = window._origBody || '';
                    document.body.style.visibility = 'visible';
                    document.querySelectorAll('[id^="cap-"]').forEach(c => c.remove());
                }""")
            except Exception:
                pass

    try:
        await page.evaluate("""() => {
            document.body.style.visibility = 'visible';
            document.querySelectorAll('[data-capture-id]').forEach(e => e.removeAttribute('data-capture-id'));
            document.querySelectorAll('[id^="cap-"]').forEach(c => c.remove());
        }""")
    except Exception:
        pass

    return elements


async def capture_background(page, html_path: Path, temp_dir: Path, visual_elements: list) -> Path:
    """Screenshot the background layer (text + visual elements hidden)."""
    try:
        await page.set_viewport_size({"width": 1920, "height": 1080})
        await page.emulate_media(media="screen")
        await page.evaluate("() => { Object.defineProperty(window, 'devicePixelRatio', { get: () => 1 }); }")
        await page.goto(f"file://{html_path.resolve()}", wait_until="networkidle", timeout=25000)
        await page.wait_for_timeout(2000)

        await page.evaluate("""(ves) => {
            function hideText(el) {
                if (el.nodeType !== 1) return;
                if (el.textContent && el.textContent.trim()) {
                    el.style.color = 'transparent';
                    el.style.textShadow = 'none';
                    el.style.webkitTextFillColor = 'transparent';
                }
                for (const ch of el.children) hideText(ch);
            }
            hideText(document.body);
            for (const v of ves) {
                if (v.width > 1700) continue;
                for (const el of document.querySelectorAll('*')) {
                    const r = el.getBoundingClientRect();
                    if (Math.abs(r.left-v.x)<5 && Math.abs(r.top-v.y)<5 &&
                        Math.abs(r.width-v.width)<5 && Math.abs(r.height-v.height)<5) {
                        el.style.visibility = 'hidden'; break;
                    }
                }
            }
        }""", visual_elements or [])

        await page.wait_for_timeout(500)
        bg_path = temp_dir / f"bg_{html_path.stem}.png"
        await page.screenshot(
            path=str(bg_path), full_page=False,
            clip={"x": 0, "y": 0, "width": 1920, "height": 1080},
        )
        return bg_path

    except Exception:
        from PIL import Image
        bg_path = temp_dir / f"bg_{html_path.stem}.png"
        Image.new("RGB", (1920, 1080), "white").save(bg_path)
        return bg_path


async def extract_text(page, html_path: Path) -> list[TextElement]:
    """Extract text elements with precise positions."""
    elements = []
    try:
        await page.set_viewport_size({"width": 1920, "height": 1080})
        await page.emulate_media(media="screen")
        await page.evaluate("() => { Object.defineProperty(window, 'devicePixelRatio', { get: () => 1 }); }")
        await page.goto(f"file://{html_path.resolve()}", wait_until="networkidle", timeout=25000)
        await page.wait_for_timeout(2000)

        data = await page.evaluate(JS_EXTRACT_TEXT)

        for d in data or []:
            if not d or not d.get("text"):
                continue
            style = d.get("style", {})
            ff = (style.get("fontFamily") or "Arial").split(",")[0].strip().strip("\"'")
            ff_map = {
                "roboto": "Roboto", "arial": "Arial", "helvetica": "Helvetica",
                "sans-serif": "Arial", "inter": "Inter",
            }
            ff = ff_map.get(ff.lower(), ff)

            lh = 1.2
            lhs = style.get("lineHeight", "normal")
            if lhs and lhs != "normal":
                if lhs.endswith("px"):
                    lh = float(lhs[:-2]) / d["fps"]
                else:
                    try:
                        lh = float(lhs)
                    except ValueError:
                        lh = 1.2

            color = style.get("color", "#000000")
            if style.get("webkitBackgroundClip") == "text" and style.get("backgroundImage"):
                m = re.search(r"#[0-9a-fA-F]{6}", style["backgroundImage"])
                color = m.group(0) if m else "#3B82F6"

            elements.append(TextElement(
                text=d["text"], x=d["x"], y=d["y"], width=d["width"], height=d["height"],
                font_family=ff, font_size=d["fps"] * 0.75, font_weight=style.get("fontWeight", "normal"),
                color=color, text_align=style.get("textAlign", "left"), line_height=lh,
                tag=d["tag"], style=style,
            ))
    except Exception:
        pass
    return elements


def add_text_box(slide, te: TextElement) -> None:
    """Create a native editable PPTX text box."""
    left = Inches(te.x / 96.0)
    top = Inches(te.y / 96.0)
    sf = max(1.0, te.font_size / 20.0)
    tw = te.width
    if tw < 100:
        tw = max(tw, len(te.text) * (8 / sf))
    pad = max(20, te.font_size * 0.5)
    width = Inches((tw + pad * 2) / 96.0)
    height = Inches(max(te.height, 10) / 96.0)

    tb = slide.shapes.add_textbox(left, top, width, height)
    tf = tb.text_frame
    tf.clear()
    tf.margin_left = tf.margin_right = tf.margin_top = tf.margin_bottom = Pt(0)
    tf.word_wrap = True
    tf.auto_size = None

    p = tf.paragraphs[0]
    text = te.text
    if te.tag == "li" and not text.startswith("•"):
        text = "• " + text
    tt = te.style.get("textTransform", "none") if te.style else "none"
    if tt == "uppercase":
        text = text.upper()
    elif tt == "lowercase":
        text = text.lower()
    elif tt == "capitalize":
        text = text.title()
    p.text = text

    align_map = {
        "left": PP_ALIGN.LEFT, "center": PP_ALIGN.CENTER, "right": PP_ALIGN.RIGHT,
        "justify": PP_ALIGN.JUSTIFY, "start": PP_ALIGN.LEFT, "end": PP_ALIGN.RIGHT,
    }
    p.alignment = align_map.get(te.text_align.lower(), PP_ALIGN.LEFT)
    p.space_before = p.space_after = Pt(0)

    font = p.font
    font.name = te.font_family
    font.size = Pt(max(te.font_size, 8))
    font.bold = is_bold(te.font_weight)

    try:
        r, g, b = parse_color(te.color)
        font.color.rgb = RGBColor(r, g, b)
    except Exception:
        font.color.rgb = RGBColor(0, 0, 0)

    tb.fill.background()
    tb.line.fill.background()


async def process_slide(context, slide_info: dict, temp_dir: Path) -> dict:
    """Process one slide: extract visuals, background, text."""
    page = await context.new_page()
    await page.set_viewport_size({"width": 1920, "height": 1080})
    await page.emulate_media(media="screen")
    await page.evaluate("() => { Object.defineProperty(window, 'devicePixelRatio', { get: () => 1 }); }")

    try:
        vis = await extract_visual_elements(page, slide_info["path"], temp_dir)
        bg = await capture_background(page, slide_info["path"], temp_dir, vis)
        txt = await extract_text(page, slide_info["path"])
        return {"slide_info": slide_info, "visual_elements": vis, "background_path": bg, "text_elements": txt}
    except Exception as e:
        return {"slide_info": slide_info, "visual_elements": [], "background_path": None, "text_elements": [], "error": str(e)}
    finally:
        await page.close()


def build_slide(prs: Presentation, analysis: dict) -> None:
    """Build one PPTX slide from analysis data."""
    layout = prs.slide_layouts[6]
    slide = prs.slides.add_slide(layout)

    bg_path = analysis.get("background_path")
    if bg_path and Path(bg_path).exists():
        slide.shapes.add_picture(str(bg_path), Inches(0), Inches(0), Inches(20), Inches(11.25))

    for ve in analysis.get("visual_elements", []):
        ip = ve.get("image_path")
        if ip and Path(ip).exists():
            slide.shapes.add_picture(
                str(ip),
                Inches(ve["x"] / 96.0), Inches(ve["y"] / 96.0),
                Inches(ve["width"] / 96.0), Inches(ve["height"] / 96.0),
            )

    for te in analysis.get("text_elements", []):
        try:
            add_text_box(slide, te)
        except Exception:
            pass


async def convert(presentation_dir: str, output_path: str) -> dict:
    """Main conversion entrypoint."""
    pres_dir = Path(presentation_dir).resolve()
    meta_path = pres_dir / "metadata.json"

    if not pres_dir.exists():
        return {"success": False, "error": f"Directory not found: {pres_dir}"}
    if not meta_path.exists():
        return {"success": False, "error": f"metadata.json not found in {pres_dir}"}

    with open(meta_path) as f:
        metadata = json.load(f)

    slides_info = []
    for num_str, data in metadata.get("slides", {}).items():
        fp = data.get("file_path", "")
        html_path = (pres_dir.parent.parent / fp) if fp else None
        if html_path and html_path.exists():
            slides_info.append({
                "number": int(num_str),
                "title": data.get("title", f"Slide {num_str}"),
                "path": html_path,
            })

    if not slides_info:
        return {"success": False, "error": "No valid slides found"}
    slides_info.sort(key=lambda s: s["number"])

    launch_opts: dict = {
        "headless": True,
        "args": [
            "--no-sandbox", "--disable-setuid-sandbox",
            "--disable-dev-shm-usage", "--disable-gpu",
            "--force-device-scale-factor=1",
        ],
    }
    chromium = find_chromium()
    if chromium:
        launch_opts["executable_path"] = chromium

    with tempfile.TemporaryDirectory() as tmp:
        tmp_path = Path(tmp)

        async with async_playwright() as p:
            browser = await p.chromium.launch(**launch_opts)
            try:
                ctx = await browser.new_context(viewport={"width": 1920, "height": 1080})
                sem = asyncio.Semaphore(5)

                async def limited(si):
                    async with sem:
                        return await process_slide(ctx, si, tmp_path)

                analyses = await asyncio.gather(*[limited(si) for si in slides_info], return_exceptions=True)
            finally:
                await browser.close()

        prs = Presentation()
        prs.slide_width = Inches(20)
        prs.slide_height = Inches(11.25)

        for i, a in enumerate(analyses):
            if isinstance(a, Exception):
                a = {"slide_info": slides_info[i], "visual_elements": [], "background_path": None, "text_elements": [], "error": str(a)}
            if a.get("error"):
                layout = prs.slide_layouts[6]
                slide = prs.slides.add_slide(layout)
                tb = slide.shapes.add_textbox(Inches(1), Inches(4), Inches(18), Inches(2))
                tb.text_frame.paragraphs[0].text = f"Error: {a['error']}"
                tb.text_frame.paragraphs[0].font.size = Pt(18)
                tb.text_frame.paragraphs[0].font.color.rgb = RGBColor(255, 0, 0)
            else:
                build_slide(prs, a)

        out = Path(output_path)
        out.parent.mkdir(parents=True, exist_ok=True)
        prs.save(str(out))

    return {"success": True, "output_path": str(out), "total_slides": len(slides_info)}


def main():
    if len(sys.argv) != 3:
        print(json.dumps({"success": False, "error": "Usage: convert_pptx.py <presentation_dir> <output_path>"}))
        sys.exit(1)

    result = asyncio.run(convert(sys.argv[1], sys.argv[2]))
    print(json.dumps(result))
    sys.exit(0 if result["success"] else 1)


if __name__ == "__main__":
    main()

# Dashboard & Data-Dense Interface Design

**Mandatory shared files (read if not already loaded):** `skills/website-building/shared/01-design-tokens.md`.

Dashboards are the most common source of broken, unusable layouts. Follow these rules strictly.

---

## Dashboard Typography & Voice

**Typography:** Use sans-serif exclusively for all UI elements — navigation, labels, data, buttons, table headers, form fields. Serif is only acceptable in a dashboard logo or decorative brand mark. Data values and numbers must use `font-variant-numeric: tabular-nums lining-nums;` so columns align and digits don't shift width.

**Logo:** When building a dashboard, generate the logo as an inline SVG. Aim for a Paul Rand-inspired aesthetic — geometric, reducible to a single shape or letterform, minimal color (one accent + black/white). The logo should work at 24px and 200px. Avoid gradients, bevels, or illustration-style complexity.

**Copy:** Dashboard copy should be active voice, concise, and scannable. Aim for a maximum of 7 words per label or sentence. Write like a control panel, not a novel:
- "Export CSV" not "Click here to export your data as a CSV file"
- "3 items need review" not "There are 3 items that are currently awaiting your review"
- "Updated 2m ago" not "This data was last updated 2 minutes ago"

---

## Layout Architecture

**The golden pattern — full-viewport, no body scroll:**
```css
html, body { height: 100%; overflow: hidden; margin: 0; }

.dashboard {
  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-rows: auto 1fr;
  height: 100dvh;
}

.sidebar {
  grid-row: 1 / -1;
  overflow-y: auto;
  overscroll-behavior: contain; /* CRITICAL */
}

.header {
  grid-column: 2;
  position: sticky; top: 0;
  z-index: 10;
}

.main {
  grid-column: 2;
  overflow-y: auto;
  overscroll-behavior: contain; /* CRITICAL */
}
```

---

## The Nested Scroll Rule

**There must be exactly ONE primary scroll region.** This is non-negotiable.

- The `<body>` should have `overflow: hidden` on dashboard layouts. Only `.main` scrolls.
- Every scrollable container must have `overscroll-behavior: contain` to prevent scroll chaining to parent elements.
- Sidebars should be fully visible without scrolling when possible. If they must scroll, they scroll independently with `overscroll-behavior: contain`.
- **Never nest a scrollable table inside a scrollable card inside a scrollable main area.** If a table overflows, the table's container scrolls horizontally while the main area handles vertical scroll.
- Modals: set `body { overflow: hidden }` when open, restore when closed.

---

## Information Hierarchy

Follow the **inverted pyramid model**:

1. **Top**: KPIs and status (the "are we on track?" line) — high-contrast cards, upper-left placement
2. **Middle**: Trends and comparisons (charts, sparklines) that explain movement
3. **Bottom**: Detail tables with sortable columns, pagination, and drill-down links

Rules:
- **Filters above content**, not hidden in sidebars. Always show what's applied.
- **Group related metrics** — separate unrelated ones with space, not lines.
- **Maximum 5-7 KPI cards** visible at once. More creates analysis paralysis.
- **Sticky table headers**: `thead { position: sticky; top: 0; z-index: 1; }`
- **Skeleton screens must match real layout** — if the skeleton has 3 bars and the content has 5 lines, you've broken the illusion.

---

## Data Visualization Rules

- **Animate number changes** — values should count up/down, not snap.
- **Delta indicators**: arrow + percentage + color (green up / red down / gray flat)
- **Sparklines in table rows** to show trends at a glance
- **Don't refresh everything simultaneously** — stagger data updates to avoid visual chaos
- **Don't rely on color alone** — always pair color with icons, labels, or patterns for accessibility

---

## Performance for Dense UIs

```css
/* Skip rendering off-screen content */
.card-grid > * {
  content-visibility: auto;
  contain-intrinsic-size: 0 200px;
}
```

`content-visibility: auto` tells the browser to skip layout/paint for off-screen elements. For dashboards with 50+ cards or long tables, this is a massive performance win (95%+ browser support).

# Shadcn Sidebar

## General Rules

- **Always** use the Shadcn sidebar located at `@/components/ui/sidebar` if your application calls for a sidebar.
- **Never** reimplement your own unless the user explicitly asks you to not use the Shadcn sidebar.
- **Never** set the width on a `<Sidebar />` component. Instead, set CSS style properties on `SidebarProvider`:

```tsx
// Bad
<Sidebar className="w-60">

// Good
const style = {
  "--sidebar-width": "20rem",      // default is 16rem
  "--sidebar-width-icon": "4rem",  // default is 3rem
};

<SidebarProvider style={style as React.CSSProperties}>
```

- You **must** supply `w-full` to the element that is the immediate child of `SidebarProvider`:

```tsx
// Good
<SidebarProvider style={style as React.CSSProperties}>
  <div className="flex h-screen w-full">
  ...

// Bad - missing w-full on child
<SidebarProvider style={style as React.CSSProperties}>
  <div className="flex h-screen">
  ...
```

## Basic Setup

### 1. Add Provider and Trigger

Add `SidebarProvider` and `SidebarTrigger` at the root of your application:

```tsx
// client/src/App.tsx
import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import NotFound from "@/pages/not-found";
import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";
import { AppSidebar } from "@/components/app-sidebar";

function Router() {
  return (
    <Switch>
      {/* <Route path="/" component={Home}/> */}
      <Route component={NotFound} />
    </Switch>
  );
}

export default function App() {
  const style = {
    "--sidebar-width": "20rem",
    "--sidebar-width-icon": "4rem",
  };

  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <SidebarProvider style={style as React.CSSProperties}>
          <div className="flex h-screen w-full">
            <AppSidebar />
            <div className="flex flex-col flex-1">
              <header className="flex items-center justify-between p-2 border-b">
                <SidebarTrigger data-testid="button-sidebar-toggle" />
                <ThemeToggle />
              </header>
              <main className="flex-1 overflow-hidden">
                <Router />
              </main>
            </div>
          </div>
        </SidebarProvider>
        <Toaster />
      </TooltipProvider>
    </QueryClientProvider>
  );
}
```

### 2. Create Sidebar Component

Create a new sidebar component at `components/app-sidebar.tsx`:

```tsx
// components/app-sidebar.tsx
import { Sidebar, SidebarContent } from "@/components/ui/sidebar";

export function AppSidebar() {
  return (
    <Sidebar>
      <SidebarContent />
    </Sidebar>
  );
}
```

### 3. Add Menu Items

Add a `SidebarMenu` inside a `SidebarGroup`:

```tsx
// components/app-sidebar.tsx
import { Calendar, Home, Inbox, Search, Settings } from "lucide-react";
import {
  Sidebar,
  SidebarContent,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar";

const items = [
  { title: "Home", url: "#", icon: Home },
  { title: "Inbox", url: "#", icon: Inbox },
  { title: "Calendar", url: "#", icon: Calendar },
  { title: "Search", url: "#", icon: Search },
  { title: "Settings", url: "#", icon: Settings },
];

export function AppSidebar() {
  return (
    <Sidebar>
      <SidebarContent>
        <SidebarGroup>
          <SidebarGroupLabel>Application</SidebarGroupLabel>
          <SidebarGroupContent>
            <SidebarMenu>
              {items.map((item) => (
                <SidebarMenuItem key={item.title}>
                  <SidebarMenuButton asChild>
                    <a href={item.url}>
                      <item.icon />
                      <span>{item.title}</span>
                    </a>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>
    </Sidebar>
  );
}
```

