"""
Shared helpers for running LibreOffice headless on Linux and macOS.
"""

import os
import platform
import subprocess
from pathlib import Path

MACRO_DIR = {
    "Darwin": "~/Library/Application Support/LibreOffice/4/user/basic/Standard",
    "Linux": "~/.config/libreoffice/4/user/basic/Standard",
}

TIMEOUT_CMD = {"Darwin": "gtimeout", "Linux": "timeout"}


def soffice_env() -> dict[str, str]:
    env = os.environ.copy()
    env["SAL_USE_VCLPLUGIN"] = "svp"
    return env


def macro_dir() -> Path:
    return Path(os.path.expanduser(MACRO_DIR.get(platform.system(), MACRO_DIR["Linux"])))


def has_timeout_cmd() -> str | None:
    cmd = TIMEOUT_CMD.get(platform.system())
    if not cmd:
        return None
    try:
        subprocess.run([cmd, "--version"], capture_output=True, timeout=1, check=False)
        return cmd
    except (FileNotFoundError, subprocess.TimeoutExpired):
        return None


def run_soffice(args: list[str], timeout: int | None = None) -> subprocess.CompletedProcess[str]:
    cmd = ["soffice", *args]

    if timeout is not None:
        timeout_cmd = has_timeout_cmd()
        if timeout_cmd:
            cmd = [timeout_cmd, str(timeout), *cmd]

    return subprocess.run(cmd, capture_output=True, text=True, env=soffice_env())

"""
Recalculate all formulas in an Excel file via LibreOffice headless, then
scan for residual errors (#REF!, #DIV/0!, etc.).

Usage:
    python recalc.py <excel_file> [timeout_seconds]
"""

import json
import re
import shutil
import subprocess
import sys
import zipfile
from pathlib import Path

from _soffice import macro_dir, run_soffice, soffice_env
from openpyxl import load_workbook

RECALC_MACRO = """\
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE script:module PUBLIC "-//OpenOffice.org//DTD OfficeDocument 1.0//EN" "module.dtd">
<script:module xmlns:script="http://openoffice.org/2000/script" \
script:name="Module1" script:language="StarBasic">
    Sub RecalculateAndSave()
      ThisComponent.calculateAll()
      ThisComponent.store()
      ThisComponent.close(True)
    End Sub
</script:module>"""

MACRO_SCRIPT_URI = "vnd.sun.star.script:Standard.Module1.RecalculateAndSave?language=Basic&location=application"

EXCEL_ERRORS = ("#VALUE!", "#DIV/0!", "#REF!", "#NAME?", "#NULL!", "#NUM!", "#N/A")

TABLE_STYLE_RE = re.compile(rb"<tableStyleInfo[^/>]*/>")

MAX_ERROR_LOCATIONS = 20

DEFAULT_TIMEOUT = 30


def _ensure_macro() -> bool:
    macro_file = macro_dir() / "Module1.xba"

    if macro_file.exists() and "RecalculateAndSave" in macro_file.read_text():
        return True

    if not macro_file.parent.exists():
        subprocess.run(
            ["soffice", "--headless", "--terminate_after_init"],
            capture_output=True,
            timeout=10,
            env=soffice_env(),
        )
        macro_file.parent.mkdir(parents=True, exist_ok=True)

    try:
        macro_file.write_text(RECALC_MACRO)
        return True
    except Exception:
        return False


def _snapshot_table_styles(path: str) -> dict[str, bytes]:
    styles: dict[str, bytes] = {}
    with zipfile.ZipFile(path, "r") as zf:
        for name in zf.namelist():
            if name.startswith("xl/tables/") and name.endswith(".xml"):
                m = TABLE_STYLE_RE.search(zf.read(name))
                if m:
                    styles[name] = m.group(0)
    return styles


def _patch_table_style(data: bytes, style_element: bytes) -> bytes:
    if TABLE_STYLE_RE.search(data):
        return TABLE_STYLE_RE.sub(style_element, data)
    return data.replace(b"</table>", style_element + b"</table>")


def _restore_table_styles(path: str, styles: dict[str, bytes]) -> None:
    if not styles:
        return

    tmp = path + ".tmp"
    try:
        with zipfile.ZipFile(path, "r") as zin, zipfile.ZipFile(tmp, "w") as zout:
            for item in zin.infolist():
                data = zin.read(item.filename)
                if item.filename in styles:
                    data = _patch_table_style(data, styles[item.filename])
                zout.writestr(item, data)
        shutil.move(tmp, path)
    except Exception:
        import os

        if os.path.exists(tmp):
            os.remove(tmp)


def _scan_errors(path: str) -> dict[str, list[str]]:
    wb = load_workbook(path, data_only=True)
    found: dict[str, list[str]] = {e: [] for e in EXCEL_ERRORS}
    for sheet_name in wb.sheetnames:
        for row in wb[sheet_name].iter_rows():
            for cell in row:
                if isinstance(cell.value, str):
                    for err in EXCEL_ERRORS:
                        if err in cell.value:
                            found[err].append(f"{sheet_name}!{cell.coordinate}")
                            break
    wb.close()
    return found


def _count_formulas(path: str) -> int:
    wb = load_workbook(path, data_only=False)
    count = 0
    for sheet_name in wb.sheetnames:
        for row in wb[sheet_name].iter_rows():
            for cell in row:
                if isinstance(cell.value, str) and cell.value.startswith("="):
                    count += 1
    wb.close()
    return count


def recalc(filename: str, timeout: int = DEFAULT_TIMEOUT) -> dict:
    path = Path(filename)
    if not path.exists():
        return {"error": f"File {filename} does not exist"}

    abs_path = str(path.absolute())

    if not _ensure_macro():
        return {"error": "Failed to setup LibreOffice macro"}

    try:
        table_styles = _snapshot_table_styles(abs_path)
    except Exception:
        table_styles = {}

    result = run_soffice(["--headless", "--norestore", MACRO_SCRIPT_URI, abs_path], timeout=timeout)

    if result.returncode not in (0, 124):
        error_msg = result.stderr or "Unknown error during recalculation"
        if "Module1" in error_msg or "RecalculateAndSave" not in error_msg:
            return {"error": "LibreOffice macro not configured properly"}
        return {"error": error_msg}

    try:
        _restore_table_styles(abs_path, table_styles)
    except Exception:
        pass

    try:
        errors = _scan_errors(abs_path)
        total_errors = sum(len(locs) for locs in errors.values())

        summary = {}
        for err_type, locations in errors.items():
            if locations:
                summary[err_type] = {
                    "count": len(locations),
                    "locations": locations[:MAX_ERROR_LOCATIONS],
                }

        return {
            "status": "success" if total_errors == 0 else "errors_found",
            "total_errors": total_errors,
            "total_formulas": _count_formulas(abs_path),
            "error_summary": summary,
        }
    except Exception as e:
        return {"error": str(e)}


def main() -> None:
    if len(sys.argv) < 2:
        print("Usage: python recalc.py <excel_file> [timeout_seconds]")
        sys.exit(1)

    filename = sys.argv[1]
    timeout = int(sys.argv[2]) if len(sys.argv) > 2 else DEFAULT_TIMEOUT
    print(json.dumps(recalc(filename, timeout), indent=2))


if __name__ == "__main__":
    main()

import { tool } from "@opencode-ai/plugin";
import { getEnv, getKortixRouterBase } from "./lib/get-env";

// People search is powered by an Apify LinkedIn-profile-search actor. Like
// web_search, it runs in two modes: through the Kortix router by default (Kortix
// injects the APIFY_TOKEN and bills the account — zero config for the user), or
// against a raw APIFY_TOKEN when KORTIX_API_URL is unset (self-host / opt-in).
//
// The search is an Apify actor "run" (not an instant API). We use the
// run-sync-get-dataset-items endpoint in "Short" mode (search pages only, no
// per-profile open) — the fastest, cheapest path (~$0.10 per 25) — and wait for
// it to finish. A run can take a while; that's expected, let it complete.

const ACTOR = "harvestapi~linkedin-profile-search";
const RUN_PATH = `/v2/acts/${ACTOR}/run-sync-get-dataset-items`;
const APIFY_DIRECT_BASE = "https://api.apify.com";

interface RawPerson {
  name?: string;
  fullName?: string;
  firstName?: string;
  lastName?: string;
  headline?: string;
  title?: string;
  occupation?: string;
  location?: string;
  locationName?: string;
  linkedinUrl?: string;
  profileUrl?: string;
  url?: string;
  publicProfileUrl?: string;
  companyName?: string;
  currentCompany?: { name?: string } | null;
  currentPosition?: { companyName?: string; title?: string } | null;
  experience?: Array<{ companyName?: string; title?: string }>;
  email?: string | null;
}

function splitList(v?: string): string[] | undefined {
  if (!v) return undefined;
  const items = v.split(",").map((s) => s.trim()).filter(Boolean);
  return items.length ? items : undefined;
}

function formatPerson(p: RawPerson) {
  return {
    name: p.name || p.fullName || [p.firstName, p.lastName].filter(Boolean).join(" ").trim(),
    title: p.headline || p.title || p.occupation || p.currentPosition?.title || "",
    company:
      p.companyName ||
      p.currentPosition?.companyName ||
      p.currentCompany?.name ||
      p.experience?.[0]?.companyName ||
      "",
    location: p.location || p.locationName || "",
    linkedin_url: p.linkedinUrl || p.profileUrl || p.publicProfileUrl || p.url || "",
    email: p.email ?? null,
  };
}

export default tool({
  description:
    "Find real people by profile — name, title, company, location, or skill — via LinkedIn profile search. " +
    "Returns structured profiles (name, title, current company, location, LinkedIn URL). " +
    "Use for sourcing / recruiting / outreach lists and named-person lookups. " +
    "Always hyperlink each person's name to their LinkedIn URL in the result.",
  args: {
    query: tool.schema
      .string()
      .describe("Free-text search: name, role, focus, or keywords (e.g. 'climate tech founder')."),
    titles: tool.schema
      .string()
      .optional()
      .describe("Comma-separated current job titles to match (e.g. 'Head of Talent,Recruiting Lead')."),
    locations: tool.schema
      .string()
      .optional()
      .describe("Comma-separated locations — city / region / country (e.g. 'Singapore')."),
    num_results: tool.schema
      .number()
      .optional()
      .describe("People to return (1-25). Default: 10"),
  },
  async execute(args, _context) {
    const routerBase = getKortixRouterBase("apify");
    const kortixToken = getEnv("KORTIX_TOKEN");
    const apifyToken = getEnv("APIFY_TOKEN");

    let url: string;
    let bearer: string;
    if (routerBase && kortixToken) {
      url = `${routerBase}${RUN_PATH}`;
      bearer = kortixToken; // the router validates this and injects the real APIFY_TOKEN
    } else if (apifyToken) {
      url = `${APIFY_DIRECT_BASE}${RUN_PATH}`;
      bearer = apifyToken;
    } else {
      return JSON.stringify(
        {
          success: false,
          error:
            "people_search is unavailable: no Kortix router (KORTIX_API_URL / KORTIX_TOKEN) and no APIFY_TOKEN set.",
        },
        null,
        2,
      );
    }

    const maxItems = Math.max(1, Math.min(args.num_results ?? 10, 25));
    const input: Record<string, unknown> = {
      profileScraperMode: "Short",
      searchQuery: args.query,
      maxItems,
    };
    const titles = splitList(args.titles);
    if (titles) input.currentJobTitles = titles;
    const locations = splitList(args.locations);
    if (locations) input.locations = locations;

    try {
      const res = await fetch(`${url}?maxItems=${maxItems}`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${bearer}` },
        body: JSON.stringify(input),
      });
      if (!res.ok) {
        const text = await res.text().catch(() => "");
        return JSON.stringify(
          { success: false, error: `people_search API error: ${res.status} ${text.slice(0, 300)}` },
          null,
          2,
        );
      }
      const data = (await res.json()) as RawPerson[] | { items?: RawPerson[] };
      const items = Array.isArray(data) ? data : (data.items ?? []);
      const results = items.map(formatPerson).filter((p) => p.name);
      return JSON.stringify(
        { success: true, query: args.query, count: results.length, results },
        null,
        2,
      );
    } catch (e) {
      return JSON.stringify({ success: false, error: String(e) }, null, 2);
    }
  },
});

